const HTML = "<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n<meta charset=\"UTF-8\"/>\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"/>\n<title>Plataforma C5 \u2014 Gesti\u00f3n de Cartera</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=DM+Sans:wght@300;400;500&display=swap\" rel=\"stylesheet\"/>\n<script src=\"https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2\"></script>\n<style>\n:root{--bg:#0a0f1e;--surface:#111827;--surface2:#1a2235;--border:#1f2d45;--accent:#00d4aa;--accent2:#0099ff;--danger:#ff4d6d;--text:#e8edf5;--text-muted:#6b7fa3;--text-dim:#3d4f6e;--radius:16px;--radius-sm:10px;}\n*{box-sizing:border-box;margin:0;padding:0;}\nbody{font-family:'DM Sans',sans-serif;background:var(--bg);color:var(--text);min-height:100vh;overflow-x:hidden;}\nbody::before{content:'';position:fixed;inset:0;background:radial-gradient(ellipse 60% 50% at 20% 20%,rgba(0,212,170,.07) 0%,transparent 60%),radial-gradient(ellipse 50% 60% at 80% 80%,rgba(0,153,255,.07) 0%,transparent 60%);pointer-events:none;z-index:0;}\n.screen{display:none;position:relative;z-index:1;min-height:100vh;}\n.screen.active{display:flex;}\n.auth-layout{flex-direction:column;align-items:center;justify-content:center;padding:24px;}\n.logo-svg{width:300px;max-width:88vw;margin-bottom:4px;}\n.logo-tagline{color:var(--text-muted);font-size:13px;margin-bottom:32px;text-align:center;letter-spacing:.04em;}\n.topbar-logo-txt{font-family:'Syne',sans-serif;font-weight:800;font-size:20px;background:linear-gradient(135deg,#00ffcc,#00aaff);-webkit-background-clip:text;-webkit-text-fill-color:transparent;}\n.card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:36px 32px;width:100%;max-width:440px;box-shadow:0 24px 64px rgba(0,0,0,.4);}\n.card-title{font-family:'Syne',sans-serif;font-weight:700;font-size:22px;margin-bottom:6px;}\n.card-sub{color:var(--text-muted);font-size:13px;margin-bottom:28px;line-height:1.5;}\n.field{margin-bottom:18px;}\n.field label{display:block;font-size:12px;font-weight:500;color:var(--text-muted);text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px;}\n.field input{width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;transition:border-color .2s,box-shadow .2s;}\n.field input:focus{border-color:var(--accent);box-shadow:0 0 0 3px rgba(0,212,170,.12);}\n.field input::placeholder{color:var(--text-dim);}\n.pass-wrap{position:relative;}\n.pass-wrap input{padding-right:44px;}\n.toggle-pass{position:absolute;right:14px;top:50%;transform:translateY(-50%);background:none;border:none;color:var(--text-muted);cursor:pointer;font-size:16px;padding:0;line-height:1;}\n.phone-wrap{display:flex;gap:8px;}\n.phone-prefix{background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 14px;color:var(--text-muted);font-size:14px;white-space:nowrap;display:flex;align-items:center;gap:6px;}\n.btn{width:100%;padding:14px;border:none;border-radius:var(--radius-sm);font-family:'Syne',sans-serif;font-weight:600;font-size:15px;cursor:pointer;transition:all .2s;}\n.btn-primary{background:linear-gradient(135deg,var(--accent),#00b894);color:#001a14;}\n.btn-primary:hover{transform:translateY(-1px);box-shadow:0 8px 24px rgba(0,212,170,.3);}\n.btn-ghost{background:transparent;color:var(--accent);border:1px solid var(--border);margin-top:12px;}\n.btn-ghost:hover{border-color:var(--accent);background:rgba(0,212,170,.06);}\n.btn:disabled{opacity:.5;cursor:not-allowed;transform:none!important;}\n.link-btn{background:none;border:none;color:var(--accent);font-size:13px;cursor:pointer;font-family:'DM Sans',sans-serif;text-decoration:underline;padding:0;}\n.steps{display:flex;gap:6px;margin-bottom:28px;}\n.step-dot{height:4px;flex:1;border-radius:2px;background:var(--border);transition:background .3s;}\n.step-dot.active{background:var(--accent);}\n.step-dot.done{background:rgba(0,212,170,.4);}\n.otp-wrap{display:flex;gap:10px;justify-content:center;margin:20px 0;}\n.otp-box{width:52px;height:60px;background:var(--surface2);border:2px solid var(--border);border-radius:var(--radius-sm);color:var(--text);font-family:'Syne',sans-serif;font-size:24px;font-weight:700;text-align:center;outline:none;transition:border-color .2s,box-shadow .2s;}\n.otp-box:focus{border-color:var(--accent);box-shadow:0 0 0 3px rgba(0,212,170,.15);}\n.toast{position:fixed;bottom:24px;left:50%;transform:translateX(-50%) translateY(100px);background:var(--surface);border:1px solid var(--border);border-radius:var(--radius-sm);padding:14px 20px;font-size:13px;z-index:9999;transition:transform .3s;max-width:360px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,.4);}\n.toast.show{transform:translateX(-50%) translateY(0);}\n.toast.success{border-color:var(--accent);color:var(--accent);}\n.toast.error{border-color:var(--danger);color:var(--danger);}\n.toast.info{border-color:var(--accent2);color:var(--accent2);}\n.divider{display:flex;align-items:center;gap:12px;margin:20px 0;color:var(--text-dim);font-size:12px;}\n.divider::before,.divider::after{content:'';flex:1;height:1px;background:var(--border);}\n.info-box{background:rgba(0,153,255,.08);border:1px solid rgba(0,153,255,.2);border-radius:var(--radius-sm);padding:12px 16px;font-size:12px;color:var(--accent2);margin-top:16px;line-height:1.6;}\n#dashboard{flex-direction:column;}\n.topbar{position:sticky;top:0;z-index:100;background:rgba(10,15,30,.9);backdrop-filter:blur(16px);border-bottom:1px solid var(--border);padding:16px 28px;display:flex;align-items:center;justify-content:space-between;}\n.topbar-logo{font-family:'Syne',sans-serif;font-weight:800;font-size:20px;background:linear-gradient(135deg,var(--accent),var(--accent2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;}\n.topbar-right{display:flex;align-items:center;gap:14px;}\n.empresa-badge{background:var(--surface2);border:1px solid var(--border);border-radius:50px;padding:6px 14px;font-size:13px;color:var(--text-muted);display:flex;align-items:center;gap:8px;}\n.empresa-dot{width:8px;height:8px;border-radius:50%;background:var(--accent);box-shadow:0 0 8px var(--accent);}\n.logout-btn{background:none;border:1px solid var(--border);border-radius:var(--radius-sm);color:var(--text-muted);padding:7px 14px;font-size:13px;cursor:pointer;font-family:'DM Sans',sans-serif;transition:all .2s;}\n.logout-btn:hover{border-color:var(--danger);color:var(--danger);}\n.dash-body{padding:36px 28px;max-width:1000px;margin:0 auto;width:100%;}\n.dash-header{display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:16px;margin-bottom:32px;}\n.dash-greeting{font-family:'Syne',sans-serif;font-weight:700;font-size:26px;margin-bottom:6px;}\n.dash-greeting span{color:var(--accent);}\n.dash-sub{color:var(--text-muted);font-size:14px;}\n.stats-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:16px;margin-bottom:32px;}\n.stat-card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:22px;position:relative;overflow:hidden;}\n.stat-card::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;}\n.stat-card.total::before{background:linear-gradient(90deg,var(--danger),#ff8fab);}\n.stat-card.count::before{background:linear-gradient(90deg,var(--accent2),#7ee8fa);}\n.stat-label{font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:var(--text-muted);margin-bottom:10px;}\n.stat-value{font-family:'Syne',sans-serif;font-weight:700;font-size:28px;line-height:1;}\n.stat-card.total .stat-value{color:var(--danger);}\n.stat-card.count .stat-value{color:var(--accent2);}\n.section-title{font-family:'Syne',sans-serif;font-weight:700;font-size:17px;margin-bottom:16px;display:flex;align-items:center;gap:10px;}\n.section-title::after{content:'';flex:1;height:1px;background:var(--border);}\n.table-wrap{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);overflow-x:auto;}\ntable{width:100%;border-collapse:collapse;font-size:13px;min-width:900px;}\nthead th{background:var(--surface2);padding:12px 14px;text-align:left;font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:var(--text-muted);font-weight:500;white-space:nowrap;}\ntbody tr{border-top:1px solid var(--border);transition:background .15s;}\ntbody tr:hover{background:rgba(255,255,255,.02);}\ntbody td{padding:13px 14px;color:var(--text);vertical-align:middle;white-space:nowrap;}\n.td-acciones{display:flex;gap:6px;align-items:center;}\n.btn-editar{background:rgba(0,153,255,.12);border:1px solid rgba(0,153,255,.3);color:var(--accent2);border-radius:6px;padding:6px 12px;font-size:12px;cursor:pointer;white-space:nowrap;font-family:'DM Sans',sans-serif;}\n.btn-eliminar{background:rgba(255,77,109,.12);border:1px solid rgba(255,77,109,.3);color:var(--danger);border-radius:6px;padding:6px 12px;font-size:12px;cursor:pointer;white-space:nowrap;font-family:'DM Sans',sans-serif;}\n.btn-editar:hover{background:rgba(0,153,255,.25);}\n.btn-eliminar:hover{background:rgba(255,77,109,.25);}\n.alerta-persona{background:rgba(255,179,71,.08);border:1px solid rgba(255,179,71,.3);border-radius:var(--radius-sm);padding:14px 16px;margin-bottom:16px;font-size:13px;}\n.alerta-persona-title{color:#ffb347;font-weight:600;margin-bottom:6px;}\n.alerta-persona-data{color:var(--text-muted);margin-bottom:10px;line-height:1.5;}\n.alerta-persona-btns{display:flex;gap:8px;flex-wrap:wrap;}\n.alerta-persona-btns button{padding:7px 14px;border-radius:6px;font-size:12px;cursor:pointer;font-family:'DM Sans',sans-serif;border:none;}\n.amount{font-family:'Syne',sans-serif;font-weight:600;}\n.empty-state{padding:60px 20px;text-align:center;color:var(--text-muted);}\n.empty-icon{font-size:40px;margin-bottom:12px;}\n.empty-text{font-size:14px;line-height:1.6;}\n.spinner{width:18px;height:18px;border:2px solid rgba(255,255,255,.2);border-top-color:currentColor;border-radius:50%;animation:spin .7s linear infinite;display:inline-block;vertical-align:middle;}\n@keyframes spin{to{transform:rotate(360deg);}}\n.loading-row td{text-align:center;padding:40px;color:var(--text-muted);}\n.modal-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.75);z-index:200;align-items:center;justify-content:center;padding:20px;}\n.modal-card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:32px;width:100%;max-width:480px;max-height:90vh;overflow-y:auto;animation:fadeUp .3s ease;box-shadow:0 24px 64px rgba(0,0,0,.5);}\n.modal-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:22px;}\n.modal-title{font-family:'Syne',sans-serif;font-weight:700;font-size:20px;}\n.modal-close{background:none;border:none;color:var(--text-muted);font-size:24px;cursor:pointer;line-height:1;padding:0;}\n@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}\n.card,.stat-card,.table-wrap{animation:fadeUp .4s ease both;}\n.stat-card:nth-child(2){animation-delay:.05s;}\n@media(max-width:600px){.card{padding:28px 20px;}.dash-body{padding:20px 14px;}.topbar{padding:14px 16px;}.otp-box{width:42px;height:52px;font-size:20px;}.empresa-badge span{display:none;}}\n</style>\n</head>\n<body>\n\n<!-- BIENVENIDA -->\n<div id=\"welcome\" class=\"screen auth-layout active\">\n\n  <svg class=\"logo-svg\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:220px;margin-bottom:4px;\">\n    <defs>\n      <linearGradient id=\"gC\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient>\n      <linearGradient id=\"g5\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient>\n    </defs>\n    <circle cx=\"75\" cy=\"60\" r=\"55\" fill=\"#00ffcc\" opacity=\"0.06\"/>\n    <circle cx=\"185\" cy=\"60\" r=\"55\" fill=\"#00aaff\" opacity=\"0.06\"/>\n    <text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#gC)\">C</text>\n    <text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#g5)\">5</text>\n  </svg>\n\n  <div class=\"logo-tagline\">Plataforma de gesti\u00f3n de cartera</div>\n\n  <!-- MENSAJE MOTIVADOR -->\n  <div style=\"max-width:680px;width:100%;margin-bottom:24px;padding:18px 24px;background:linear-gradient(135deg,rgba(0,212,170,.08),rgba(0,153,255,.08));border:1px solid rgba(0,212,170,.2);border-radius:16px;text-align:center;\">\n    <div style=\"font-family:'Syne',sans-serif;font-weight:700;font-size:16px;color:var(--text);margin-bottom:8px;line-height:1.4;\">\n      \u00bfTienes clientes con deudas de m\u00e1s de 2 meses? <span style=\"color:var(--accent);\">\u00a1Rep\u00f3rtalos!</span>\n    </div>\n    <div style=\"font-size:13px;color:var(--text-muted);line-height:1.6;\">\n      \u00bfVas a hacer un cr\u00e9dito? <strong style=\"color:var(--accent2);\">Verifica primero a tu cliente.</strong><br>\n      <span style=\"color:var(--accent);font-weight:600;\">En C5 est\u00e1 todo.</span>\n    </div>\n  </div>\n\n\n    <div class=\"card\" style=\"flex:1;min-width:260px;max-width:340px;\">\n      <div style=\"font-size:32px;margin-bottom:10px;\">\ud83c\udfe2</div>\n      <div class=\"card-title\" style=\"font-size:18px;\">Empresa / Negocio / Oficina</div>\n      <div class=\"card-sub\">Gestiona tu cartera, reporta obligaciones en mora y recibe notificaciones de negociaci\u00f3n.</div>\n      <button class=\"btn btn-primary\" onclick=\"document.querySelectorAll('.screen').forEach(function(s){s.classList.remove('active')});document.getElementById('login').classList.add('active');window.scrollTo(0,0);\">Iniciar sesi\u00f3n</button>\n      <button class=\"btn btn-ghost\" onclick=\"document.querySelectorAll('.screen').forEach(function(s){s.classList.remove('active')});document.getElementById('reg-step1').classList.add('active');window.scrollTo(0,0);\">Registrarse</button>\n    </div>\n\n    <!-- CARD CONSULTA UNIFICADA -->\n    <div class=\"card\" style=\"flex:1;min-width:260px;max-width:340px;\">\n      <div style=\"font-size:32px;margin-bottom:10px;\">\ud83d\udd0d</div>\n      <div class=\"card-title\" style=\"font-size:18px;\">Consultar documento</div>\n      <div class=\"card-sub\">Verifica si un documento tiene obligaciones reportadas en el sistema.</div>\n      <div class=\"field\" style=\"margin-top:4px;\">\n        <label>Tipo de documento</label>\n        <select id=\"v-tipo-doc\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\">\n          <option value=\"\">Selecciona...</option>\n        </select>\n      </div>\n      <div class=\"field\">\n        <label>N\u00famero de documento</label>\n        <input type=\"text\" id=\"v-documento\" placeholder=\"Ej: 1234567890\" inputmode=\"numeric\"\n          autocomplete=\"new-password\" autocorrect=\"off\" autocapitalize=\"off\"\n          spellcheck=\"false\" name=\"search_doc_x\" readonly\n          onfocus=\"this.removeAttribute('readonly')\"/>\n      </div>\n      <button class=\"btn btn-primary\" onclick=\"verificarPersona()\" id=\"btn-verificar\" style=\"background:linear-gradient(135deg,var(--accent2),#0055ff);\">\ud83d\udd0d Consultar</button>\n      <div id=\"v-resultado\" style=\"margin-top:16px;display:none;\"></div>\n      <div style=\"margin-top:12px;padding:10px;background:rgba(0,153,255,.06);border:1px solid rgba(0,153,255,.15);border-radius:10px;font-size:11px;color:var(--text-muted);line-height:1.6;text-align:center;\">\n        3 consultas gratuitas al mes. <button onclick=\"showScreen('reg-step1')\" style=\"background:none;border:none;color:var(--accent);font-size:11px;cursor:pointer;text-decoration:underline;padding:0;\">Reg\u00edstrate</button> para obtener m\u00e1s.\n      </div>\n    </div>\n\n</div>\n\n<!-- LOGIN -->\n<div id=\"login\" class=\"screen auth-layout\">\n  <svg class=\"logo-svg\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:220px;margin-bottom:4px;\">\n  <defs>\n    <linearGradient id=\"gC\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient>\n    <linearGradient id=\"g5\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient>\n  </defs>\n  <circle cx=\"75\" cy=\"60\" r=\"55\" fill=\"#00ffcc\" opacity=\"0.06\"/>\n  <circle cx=\"185\" cy=\"60\" r=\"55\" fill=\"#00aaff\" opacity=\"0.06\"/>\n  <text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#gC)\">C</text>\n  <text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#g5)\">5</text>\n</svg>\n  <div class=\"logo-tagline\">Ingresa a tu cuenta empresarial</div>\n  <div class=\"card\">\n    <div class=\"card-title\">Iniciar sesi\u00f3n</div>\n    <div class=\"card-sub\">Usa tu celular y contrase\u00f1a para ingresar.</div>\n    <div class=\"field\"><label>Celular *</label>\n      <div class=\"phone-wrap\"><div class=\"phone-prefix\">\ud83c\udde8\ud83c\uddf4 +57</div><input type=\"tel\" id=\"login-celular\" placeholder=\"300 123 4567\" maxlength=\"10\" inputmode=\"numeric\" autocomplete=\"new-password\" readonly onfocus=\"this.removeAttribute('readonly')\"/></div>\n    </div>\n    <div class=\"field\"><label>Contrase\u00f1a</label>\n      <div class=\"pass-wrap\"><input type=\"password\" id=\"login-pass\" placeholder=\"Tu contrase\u00f1a\" autocomplete=\"current-password\"/><button class=\"toggle-pass\" type=\"button\" onclick=\"togglePass('login-pass',this)\">\ud83d\udc41</button></div>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"hacerLogin()\" id=\"btn-login\">Ingresar</button>\n    <div style=\"text-align:center;margin-top:16px;\"><button class=\"link-btn\" onclick=\"showScreen('forgot')\">\u00bfOlvidaste tu contrase\u00f1a?</button></div>\n    <div class=\"divider\">\u00bfNo tienes cuenta?</div>\n    <button class=\"btn btn-ghost\" onclick=\"showScreen('reg-step1')\">Registrarse</button>\n    <button class=\"btn btn-ghost\" onclick=\"showScreen('welcome')\" style=\"margin-top:8px;\">\u2190 Volver</button>\n  </div>\n</div>\n\n<!-- REGISTRO PASO 1 -->\n<div id=\"reg-step1\" class=\"screen auth-layout\">\n  <svg class=\"logo-svg\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:220px;margin-bottom:4px;\">\n  <defs>\n    <linearGradient id=\"gC\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient>\n    <linearGradient id=\"g5\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient>\n  </defs>\n  <circle cx=\"75\" cy=\"60\" r=\"55\" fill=\"#00ffcc\" opacity=\"0.06\"/>\n  <circle cx=\"185\" cy=\"60\" r=\"55\" fill=\"#00aaff\" opacity=\"0.06\"/>\n  <text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#gC)\">C</text>\n  <text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#g5)\">5</text>\n</svg>\n  <div class=\"logo-tagline\">Crea tu cuenta empresarial</div>\n  <div class=\"card\">\n    <div class=\"steps\"><div class=\"step-dot active\"></div><div class=\"step-dot\"></div><div class=\"step-dot\"></div></div>\n    <div class=\"card-title\">Datos de la empresa</div>\n    <div class=\"card-sub\">Paso 1 de 3 \u2014 Informaci\u00f3n b\u00e1sica</div>\n    <div class=\"field\"><label>Nombre de la empresa *</label><input type=\"text\" id=\"reg-nombre\" placeholder=\"Ej: Inversiones Diomedez SAS\"/></div>\n    <div class=\"field\"><label>Celular *</label>\n      <div class=\"phone-wrap\"><div class=\"phone-prefix\">\ud83c\udde8\ud83c\uddf4 +57</div><input type=\"tel\" id=\"reg-celular\" placeholder=\"300 123 4567\" maxlength=\"10\" inputmode=\"numeric\" autocomplete=\"new-password\" readonly onfocus=\"this.removeAttribute('readonly')\"/></div>\n    </div>\n    <div class=\"field\"><label>Nombre del responsable <span style=\"color:var(--text-dim);font-size:11px;\">(opcional)</span></label><input type=\"text\" id=\"reg-responsable\" placeholder=\"Nombre completo\"/></div>\n    <button class=\"btn btn-primary\" onclick=\"regPaso1()\">Continuar \u2192</button>\n    <button class=\"btn btn-ghost\" onclick=\"showScreen('welcome')\">\u2190 Volver</button>\n  </div>\n</div>\n\n<!-- REGISTRO PASO 2 -->\n<div id=\"reg-step2\" class=\"screen auth-layout\">\n  <svg class=\"logo-svg\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:220px;margin-bottom:4px;\">\n  <defs>\n    <linearGradient id=\"gC\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient>\n    <linearGradient id=\"g5\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient>\n  </defs>\n  <circle cx=\"75\" cy=\"60\" r=\"55\" fill=\"#00ffcc\" opacity=\"0.06\"/>\n  <circle cx=\"185\" cy=\"60\" r=\"55\" fill=\"#00aaff\" opacity=\"0.06\"/>\n  <text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#gC)\">C</text>\n  <text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#g5)\">5</text>\n</svg>\n  <div class=\"logo-tagline\">Crea tu cuenta empresarial</div>\n  <div class=\"card\">\n    <div class=\"steps\"><div class=\"step-dot done\"></div><div class=\"step-dot active\"></div><div class=\"step-dot\"></div></div>\n    <div class=\"card-title\">Crea tu contrase\u00f1a</div>\n    <div class=\"card-sub\">Paso 2 de 3 \u2014 Elige una contrase\u00f1a para ingresar</div>\n    <div class=\"field\"><label>Contrase\u00f1a * (m\u00ednimo 8 caracteres)</label>\n      <div class=\"pass-wrap\"><input type=\"password\" id=\"reg-pass\" placeholder=\"M\u00ednimo 8 caracteres\" autocomplete=\"new-password\"/><button class=\"toggle-pass\" type=\"button\" onclick=\"togglePass('reg-pass',this)\">\ud83d\udc41</button></div>\n    </div>\n    <div class=\"field\"><label>Confirmar contrase\u00f1a *</label>\n      <div class=\"pass-wrap\"><input type=\"password\" id=\"reg-pass2\" placeholder=\"Repite tu contrase\u00f1a\" autocomplete=\"new-password\"/><button class=\"toggle-pass\" type=\"button\" onclick=\"togglePass('reg-pass2',this)\">\ud83d\udc41</button></div>\n    </div>\n    <div style=\"margin-bottom:18px;display:flex;align-items:flex-start;gap:10px;\">\n      <input type=\"checkbox\" id=\"reg-terminos\" style=\"margin-top:3px;width:16px;height:16px;accent-color:var(--accent);cursor:pointer;flex-shrink:0;\"/>\n      <label for=\"reg-terminos\" style=\"font-size:12px;color:var(--text-muted);line-height:1.5;cursor:pointer;\">\n        He le\u00eddo y acepto los <button type=\"button\" onclick=\"abrirTerminos()\" style=\"background:none;border:none;color:var(--accent);font-size:12px;cursor:pointer;text-decoration:underline;padding:0;\">T\u00e9rminos y Condiciones</button> de Clavo5. Declaro que la informaci\u00f3n que registre es ver\u00eddica y asumo la responsabilidad legal de los reportes realizados.\n      </label>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"regPaso2()\" id=\"btn-reg2\">Continuar \u2192</button>\n    <button class=\"btn btn-ghost\" onclick=\"showScreen('reg-step1')\">\u2190 Volver</button>\n  </div>\n</div>\n\n<!-- REGISTRO PASO 3 \u2014 OTP -->\n<div id=\"reg-step3\" class=\"screen auth-layout\">\n  <svg class=\"logo-svg\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:220px;margin-bottom:4px;\">\n  <defs>\n    <linearGradient id=\"gC3\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient>\n    <linearGradient id=\"g53\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient>\n  </defs>\n  <circle cx=\"75\" cy=\"60\" r=\"55\" fill=\"#00ffcc\" opacity=\"0.06\"/>\n  <circle cx=\"185\" cy=\"60\" r=\"55\" fill=\"#00aaff\" opacity=\"0.06\"/>\n  <text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#gC3)\">C</text>\n  <text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#g53)\">5</text>\n</svg>\n  <div class=\"logo-tagline\">Crea tu cuenta empresarial</div>\n  <div class=\"card\">\n    <div class=\"steps\"><div class=\"step-dot done\"></div><div class=\"step-dot done\"></div><div class=\"step-dot active\"></div></div>\n    <div class=\"card-title\">Verifica tu celular</div>\n    <div class=\"card-sub\" id=\"reg-otp-desc\">Ingresa el c\u00f3digo de 6 d\u00edgitos enviado a tu celular.</div>\n    <div class=\"otp-wrap\">\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'ro',0)\" id=\"ro0\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'ro',1)\" id=\"ro1\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'ro',2)\" id=\"ro2\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'ro',3)\" id=\"ro3\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'ro',4)\" id=\"ro4\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'ro',5)\" id=\"ro5\"/>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"regVerificarOTP()\" id=\"btn-reg3\">Verificar y crear cuenta</button>\n    <div style=\"text-align:center;margin-top:14px;\">\n      <button class=\"link-btn\" onclick=\"reenviarOTP()\">Reenviar c\u00f3digo</button>\n    </div>\n    <button class=\"btn btn-ghost\" onclick=\"showScreen('reg-step2')\">\u2190 Volver</button>\n    <div class=\"info-box\" id=\"otp-demo-box\" style=\"display:none;\">\n      \ud83d\udcf1 <strong>Modo demo \u2014 Tu c\u00f3digo es:</strong>\n      <div style=\"font-size:28px;font-weight:800;letter-spacing:6px;color:var(--accent);margin:8px 0;\" id=\"otp-demo-code\"></div>\n      <span style=\"font-size:11px;opacity:.7;\">En producci\u00f3n llegar\u00eda por SMS al +57 <span id=\"otp-demo-cel\"></span></span>\n    </div>\n  </div>\n</div>\n\n\n<!-- RECUPERAR CONTRASE\u00d1A - PASO 1 -->\n<div id=\"forgot\" class=\"screen auth-layout\">\n  <svg class=\"logo-svg\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:220px;margin-bottom:4px;\">\n  <defs>\n    <linearGradient id=\"gC\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient>\n    <linearGradient id=\"g5\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient>\n  </defs>\n  <circle cx=\"75\" cy=\"60\" r=\"55\" fill=\"#00ffcc\" opacity=\"0.06\"/>\n  <circle cx=\"185\" cy=\"60\" r=\"55\" fill=\"#00aaff\" opacity=\"0.06\"/>\n  <text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#gC)\">C</text>\n  <text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#g5)\">5</text>\n</svg>\n  <div class=\"logo-tagline\">Recupera tu acceso</div>\n  <div class=\"card\">\n    <div class=\"card-title\">Olvid\u00e9 mi contrase\u00f1a</div>\n    <div class=\"card-sub\">Ingresa tu celular y te enviaremos un c\u00f3digo de verificaci\u00f3n por SMS.</div>\n    <div class=\"field\"><label>Celular *</label>\n      <div class=\"phone-wrap\"><div class=\"phone-prefix\">\ud83c\udde8\ud83c\uddf4 +57</div><input type=\"tel\" id=\"forgot-celular\" placeholder=\"300 123 4567\" maxlength=\"10\" inputmode=\"numeric\" autocomplete=\"off\" readonly onfocus=\"this.removeAttribute('readonly')\"/></div>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"enviarOTPRecuperacion()\" id=\"btn-forgot\">Enviar c\u00f3digo SMS</button>\n    <button class=\"btn btn-ghost\" onclick=\"showScreen('login')\">\u2190 Volver al login</button>\n    <div class=\"info-box\" id=\"forgot-demo-box\" style=\"display:none;\">\n      \ud83d\udcf1 <strong>Modo demo \u2014 Tu c\u00f3digo es:</strong>\n      <div style=\"font-size:28px;font-weight:800;letter-spacing:6px;color:var(--accent);margin:8px 0;\" id=\"forgot-demo-code\"></div>\n    </div>\n  </div>\n</div>\n\n<!-- RECUPERAR CONTRASE\u00d1A - PASO 2 OTP -->\n<div id=\"forgot-otp\" class=\"screen auth-layout\">\n  <svg class=\"logo-svg\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:220px;margin-bottom:4px;\">\n  <defs>\n    <linearGradient id=\"gCf\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient>\n    <linearGradient id=\"g5f\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient>\n  </defs>\n  <circle cx=\"75\" cy=\"60\" r=\"55\" fill=\"#00ffcc\" opacity=\"0.06\"/>\n  <circle cx=\"185\" cy=\"60\" r=\"55\" fill=\"#00aaff\" opacity=\"0.06\"/>\n  <text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#gCf)\">C</text>\n  <text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#g5f)\">5</text>\n</svg>\n  <div class=\"logo-tagline\">Recupera tu acceso</div>\n  <div class=\"card\">\n    <div class=\"card-title\">Verifica tu celular</div>\n    <div class=\"card-sub\" id=\"forgot-otp-desc\">Ingresa el c\u00f3digo de 6 d\u00edgitos enviado por SMS.</div>\n    <div class=\"otp-wrap\">\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'fo',0)\" id=\"fo0\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'fo',1)\" id=\"fo1\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'fo',2)\" id=\"fo2\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'fo',3)\" id=\"fo3\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'fo',4)\" id=\"fo4\"/>\n      <input class=\"otp-box\" maxlength=\"1\" inputmode=\"numeric\" oninput=\"otpNext(this,'fo',5)\" id=\"fo5\"/>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"verificarOTPRecuperacion()\" id=\"btn-forgot-otp\">Verificar c\u00f3digo</button>\n    <div style=\"text-align:center;margin-top:14px;\">\n      <button class=\"link-btn\" onclick=\"enviarOTPRecuperacion()\">Reenviar c\u00f3digo</button>\n    </div>\n    <button class=\"btn btn-ghost\" onclick=\"showScreen('forgot')\">\u2190 Volver</button>\n  </div>\n</div>\n\n<!-- RECUPERAR CONTRASE\u00d1A - PASO 3 NUEVA CONTRASE\u00d1A -->\n<div id=\"forgot-newpass\" class=\"screen auth-layout\">\n  <svg class=\"logo-svg\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:220px;margin-bottom:4px;\">\n  <defs>\n    <linearGradient id=\"gCn\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient>\n    <linearGradient id=\"g5n\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient>\n  </defs>\n  <circle cx=\"75\" cy=\"60\" r=\"55\" fill=\"#00ffcc\" opacity=\"0.06\"/>\n  <circle cx=\"185\" cy=\"60\" r=\"55\" fill=\"#00aaff\" opacity=\"0.06\"/>\n  <text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#gCn)\">C</text>\n  <text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#g5n)\">5</text>\n</svg>\n  <div class=\"logo-tagline\">Recupera tu acceso</div>\n  <div class=\"card\">\n    <div class=\"card-title\">Nueva contrase\u00f1a</div>\n    <div class=\"card-sub\">Crea tu nueva contrase\u00f1a de acceso.</div>\n    <div class=\"field\"><label>Nueva contrase\u00f1a * (m\u00ednimo 8 caracteres)</label>\n      <div class=\"pass-wrap\"><input type=\"password\" id=\"new-pass\" placeholder=\"M\u00ednimo 8 caracteres\" autocomplete=\"new-password\"/><button class=\"toggle-pass\" type=\"button\" onclick=\"togglePass('new-pass',this)\">\ud83d\udc41</button></div>\n    </div>\n    <div class=\"field\"><label>Confirmar contrase\u00f1a *</label>\n      <div class=\"pass-wrap\"><input type=\"password\" id=\"new-pass2\" placeholder=\"Repite tu contrase\u00f1a\" autocomplete=\"new-password\"/><button class=\"toggle-pass\" type=\"button\" onclick=\"togglePass('new-pass2',this)\">\ud83d\udc41</button></div>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"guardarNuevaContrasena()\" id=\"btn-newpass\">Guardar contrase\u00f1a</button>\n  </div>\n</div>\n\n<!-- DASHBOARD -->\n<div id=\"dashboard\" class=\"screen\">\n  <div class=\"topbar\">\n    <div class=\"topbar-logo\"><svg style=\"width:70px;vertical-align:middle\" viewBox=\"0 0 260 120\" xmlns=\"http://www.w3.org/2000/svg\"><defs><linearGradient id=\"tgC\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00ffcc\"/><stop offset=\"100%\" stop-color=\"#00c8ff\"/></linearGradient><linearGradient id=\"tg5\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\"><stop offset=\"0%\" stop-color=\"#00aaff\"/><stop offset=\"100%\" stop-color=\"#00ffcc\"/></linearGradient></defs><text x=\"75\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#tgC)\">C</text><text x=\"185\" y=\"98\" font-family=\"Syne,sans-serif\" font-weight=\"800\" font-size=\"100\" text-anchor=\"middle\" fill=\"url(#tg5)\">5</text></svg></div>\n    <div class=\"topbar-right\">\n      <div class=\"empresa-badge\"><div class=\"empresa-dot\"></div><span id=\"dash-empresa-nombre\">Empresa</span></div>\n      <button onclick=\"verPlanes()\" style=\"background:linear-gradient(135deg,var(--accent),#00b894);border:none;color:#001a14;border-radius:var(--radius-sm);padding:7px 14px;font-size:13px;cursor:pointer;font-family:'Syne',sans-serif;font-weight:600;\">\u2b50 Planes</button>\n      <button onclick=\"verSolicitudes()\" style=\"background:rgba(255,179,71,.12);border:1px solid rgba(255,179,71,.3);color:#ffb347;border-radius:var(--radius-sm);padding:7px 14px;font-size:13px;cursor:pointer;font-family:'DM Sans',sans-serif;\" id=\"btn-solicitudes\">\ud83d\udccb Solicitudes</button>\n      <button class=\"logout-btn\" onclick=\"hacerLogout()\">Salir</button>\n    </div>\n  </div>\n  <div class=\"dash-body\">\n    <div class=\"dash-header\">\n      <div>\n        <div class=\"dash-greeting\">Hola, <span id=\"dash-responsable\">\u2014</span> \ud83d\udc4b</div>\n        <div class=\"dash-sub\" id=\"dash-info\">\u2014</div>\n      </div>\n      <button class=\"btn btn-primary\" style=\"width:auto;padding:12px 22px;font-size:14px;\" onclick=\"abrirModalNuevo()\">+ Reportar moroso</button>\n      <button onclick=\"exportarExcel()\" style=\"background:rgba(0,212,170,.12);border:1px solid rgba(0,212,170,.3);color:var(--accent);border-radius:var(--radius-sm);padding:10px 16px;font-size:13px;cursor:pointer;font-family:'DM Sans',sans-serif;\">\ud83d\udce5 Exportar</button>\n      <button onclick=\"document.getElementById('modal-masiva').style.display='flex'\" style=\"background:rgba(0,153,255,.12);border:1px solid rgba(0,153,255,.3);color:var(--accent2);border-radius:var(--radius-sm);padding:10px 16px;font-size:13px;cursor:pointer;font-family:'DM Sans',sans-serif;\">\ud83d\udcca Masiva</button>\n    </div>\n    <div class=\"stats-grid\">\n      <div class=\"stat-card total\"><div class=\"stat-label\">Total en mora</div><div class=\"stat-value\" id=\"stat-total\">$0</div></div>\n      <div class=\"stat-card count\"><div class=\"stat-label\">Personas morosas</div><div class=\"stat-value\" id=\"stat-count\">0</div></div>\n    </div>\n    <div class=\"section-title\">Listado de personas morosas</div>\n    <!-- B\u00fasqueda -->\n    <div style=\"margin-bottom:14px;display:flex;gap:10px;flex-wrap:wrap;\">\n      <input type=\"text\" id=\"search-input\" placeholder=\"\ud83d\udd0d Buscar por nombre o documento...\" \n        oninput=\"filtrarMorosos()\"\n        style=\"flex:1;min-width:200px;background:var(--surface);border:1px solid var(--border);border-radius:var(--radius-sm);padding:11px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\"/>\n      <button onclick=\"limpiarBusqueda()\" \n        style=\"background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:11px 16px;color:var(--text-muted);font-size:13px;cursor:pointer;font-family:'DM Sans',sans-serif;\">\n        Limpiar\n      </button>\n    </div>\n    <div class=\"table-wrap\">\n      <table>\n        <thead><tr><th>Cr\u00e9dito</th><th>Nombre</th><th>Documento</th><th>Departamento</th><th>Ciudad</th><th>Valor deuda</th><th>Vencimiento</th><th>Observaci\u00f3n</th><th></th></tr></thead>\n        <tbody id=\"morosos-tbody\"><tr class=\"loading-row\"><td colspan=\"9\"><span class=\"spinner\"></span> Cargando...</td></tr></tbody>\n      </table>\n    </div>\n  </div>\n</div>\n\n<!-- MODAL NUEVO MOROSO -->\n<div class=\"modal-overlay\" id=\"modal-nuevo\">\n  <div class=\"modal-card\">\n    <div class=\"modal-header\"><div class=\"modal-title\">Reportar persona morosa</div><button class=\"modal-close\" onclick=\"cerrarModal('modal-nuevo')\">\u00d7</button></div>\n    <div class=\"field\">\n      <label>Tipo de documento *</label>\n      <select id=\"m-tipo-doc\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\">\n        <option value=\"\">Selecciona...</option>\n      </select>\n    </div>\n    <div class=\"field\">\n      <label>N\u00famero de documento *</label>\n      <input type=\"text\" id=\"m-documento\" placeholder=\"Ej: 1234567890\" inputmode=\"numeric\" onblur=\"buscarPersonaExistente()\"/>\n    </div>\n    <!-- Alerta persona existente -->\n    <div id=\"alerta-persona\" class=\"alerta-persona\" style=\"display:none;\">\n      <div class=\"alerta-persona-title\">\u26a0 Este documento ya est\u00e1 registrado</div>\n      <div style=\"font-size:12px;color:var(--text-muted);margin-bottom:10px;\">Selecciona el nombre con el que deseas registrar a esta persona:</div>\n      <div class=\"alerta-persona-data\" id=\"alerta-persona-data\"></div>\n      <div style=\"margin-top:10px;\">\n        <button onclick=\"ocultarAlertaPersona()\" style=\"background:rgba(255,179,71,.12);border:1px solid rgba(255,179,71,.3);color:#ffb347;border-radius:8px;padding:8px 14px;font-size:12px;cursor:pointer;font-family:'DM Sans',sans-serif;\">Ingresar nombre diferente</button>\n      </div>\n    </div>\n    <div class=\"field\"><label>Nombre completo *</label><input type=\"text\" id=\"m-nombre\" placeholder=\"Ej: Juan Perez Garcia\"/></div>\n    <div class=\"field\">\n      <label>Departamento *</label>\n      <select id=\"m-depto\" onchange=\"cargarMunicipios()\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\">\n        <option value=\"\">Selecciona departamento...</option>\n      </select>\n    </div>\n    <div class=\"field\">\n      <label>Municipio *</label>\n      <select id=\"m-mpio\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\">\n        <option value=\"\">Selecciona municipio...</option>\n      </select>\n    </div>\n    <div class=\"field\"><label>Valor de la deuda *</label><input type=\"text\" id=\"m-valor\" placeholder=\"Ej: 1.000.000\" inputmode=\"numeric\" oninput=\"formatearMiles(this)\"/></div>\n    <div class=\"field\"><label>Fecha de vencimiento * <span style=\"color:var(--text-dim);font-size:11px;\">(m\u00edn. 2 meses de antig\u00fcedad)</span></label>\n      <div style=\"display:grid;grid-template-columns:2fr 2fr 3fr;gap:8px;\">\n        <select id=\"m-fecha-dia\" style=\"background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:11px 8px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13px;outline:none;\"><option value=\"\">D\u00eda</option></select>\n        <select id=\"m-fecha-mes\" onchange=\"actualizarDiasFecha('m')\" style=\"background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:11px 8px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13px;outline:none;\">\n          <option value=\"\">Mes</option>\n          <option value=\"1\">Enero</option><option value=\"2\">Febrero</option><option value=\"3\">Marzo</option>\n          <option value=\"4\">Abril</option><option value=\"5\">Mayo</option><option value=\"6\">Junio</option>\n          <option value=\"7\">Julio</option><option value=\"8\">Agosto</option><option value=\"9\">Septiembre</option>\n          <option value=\"10\">Octubre</option><option value=\"11\">Noviembre</option><option value=\"12\">Diciembre</option>\n        </select>\n        <select id=\"m-fecha-anio\" style=\"background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:11px 8px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13px;outline:none;\"><option value=\"\">A\u00f1o</option></select>\n      </div>\n    </div>\n    <div class=\"field\"><label>Observacion</label><input type=\"text\" id=\"m-obs\" placeholder=\"Ej: Cuota pendiente enero\"/></div>\n    <div class=\"field\">\n      <label>Celular del deudor <span style=\"color:var(--text-dim);font-size:11px;\">(opcional \u2014 solo visible para tu empresa)</span></label>\n      <div class=\"phone-wrap\"><div class=\"phone-prefix\">\ud83c\udde8\ud83c\uddf4 +57</div><input type=\"tel\" id=\"m-celular-deudor\" placeholder=\"300 123 4567\" maxlength=\"10\" inputmode=\"numeric\" autocomplete=\"off\" oninput=\"toggleSMScheck()\"/></div>\n    </div>\n    <div id=\"sms-notif-wrap\" style=\"display:none;background:rgba(0,212,170,.06);border:1px solid rgba(0,212,170,.2);border-radius:10px;padding:12px;margin-bottom:16px;\">\n      <label style=\"display:flex;align-items:center;gap:10px;cursor:pointer;\">\n        <input type=\"checkbox\" id=\"m-enviar-sms\" style=\"width:16px;height:16px;accent-color:var(--accent);cursor:pointer;flex-shrink:0;\"/>\n        <span style=\"font-size:13px;color:var(--text);\">\n          \ud83d\udcf1 Notificar al deudor por SMS \u2014 <strong style=\"color:var(--accent);\">$1.000</strong>\n          <div style=\"font-size:11px;color:var(--text-muted);margin-top:2px;\">El deudor recibir\u00e1 un mensaje informando que fue reportado en Plataforma C5</div>\n        </span>\n      </label>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"guardarMoroso()\" id=\"btn-guardar\">Guardar reporte</button>\n    <button class=\"btn btn-ghost\" onclick=\"cerrarModal('modal-nuevo')\">Cancelar</button>\n  </div>\n</div>\n\n<!-- MODAL EDITAR DEUDA -->\n<div class=\"modal-overlay\" id=\"modal-editar\">\n  <div class=\"modal-card\">\n    <div class=\"modal-header\"><div class=\"modal-title\">Editar reporte</div><button class=\"modal-close\" onclick=\"cerrarModal('modal-editar')\">\u00d7</button></div>\n    <input type=\"hidden\" id=\"e-deuda-id\"/>\n    <input type=\"hidden\" id=\"e-persona-id\"/>\n    <div class=\"field\">\n      <label>Tipo de documento *</label>\n      <select id=\"e-tipo-doc\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\"></select>\n    </div>\n    <div class=\"field\"><label>N\u00famero de documento *</label><input type=\"text\" id=\"e-documento\" inputmode=\"numeric\"/></div>\n    <div class=\"field\"><label>Nombre completo *</label><input type=\"text\" id=\"e-nombre\"/></div>\n    <div class=\"field\">\n      <label>Departamento *</label>\n      <select id=\"e-depto\" onchange=\"cargarMunicipiosEditar()\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\"></select>\n    </div>\n    <div class=\"field\">\n      <label>Municipio *</label>\n      <select id=\"e-mpio\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\"></select>\n    </div>\n    <div class=\"field\"><label>Valor de la deuda *</label><input type=\"text\" id=\"e-valor\" inputmode=\"numeric\" oninput=\"formatearMiles(this)\"/></div>\n    <div class=\"field\"><label>Fecha de vencimiento * <span style=\"color:var(--text-dim);font-size:11px;\">(m\u00edn. 2 meses de antig\u00fcedad)</span></label>\n      <div style=\"display:grid;grid-template-columns:2fr 2fr 3fr;gap:8px;\">\n        <select id=\"e-fecha-dia\" style=\"background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:11px 8px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13px;outline:none;\"><option value=\"\">D\u00eda</option></select>\n        <select id=\"e-fecha-mes\" onchange=\"actualizarDiasFecha('e')\" style=\"background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:11px 8px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13px;outline:none;\">\n          <option value=\"\">Mes</option>\n          <option value=\"1\">Enero</option><option value=\"2\">Febrero</option><option value=\"3\">Marzo</option>\n          <option value=\"4\">Abril</option><option value=\"5\">Mayo</option><option value=\"6\">Junio</option>\n          <option value=\"7\">Julio</option><option value=\"8\">Agosto</option><option value=\"9\">Septiembre</option>\n          <option value=\"10\">Octubre</option><option value=\"11\">Noviembre</option><option value=\"12\">Diciembre</option>\n        </select>\n        <select id=\"e-fecha-anio\" style=\"background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:11px 8px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:13px;outline:none;\"><option value=\"\">A\u00f1o</option></select>\n      </div>\n    </div>\n    <div class=\"field\"><label>Observaci\u00f3n</label><input type=\"text\" id=\"e-obs\"/></div>\n    <div class=\"field\">\n      <label>Celular del deudor <span style=\"color:var(--text-dim);font-size:11px;\">(opcional)</span></label>\n      <div class=\"phone-wrap\"><div class=\"phone-prefix\">\ud83c\udde8\ud83c\uddf4 +57</div><input type=\"tel\" id=\"e-celular-deudor\" maxlength=\"10\" inputmode=\"numeric\" autocomplete=\"off\"/></div>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"actualizarMoroso()\" id=\"btn-actualizar\">Guardar cambios</button>\n    <button class=\"btn btn-ghost\" onclick=\"cerrarModal('modal-editar')\">Cancelar</button>\n  </div>\n</div>\n\n<!-- MODAL T\u00c9RMINOS Y CONDICIONES -->\n<div class=\"modal-overlay\" id=\"modal-terminos\">\n  <div class=\"modal-card\" style=\"max-width:560px;\">\n    <div class=\"modal-header\">\n      <div class=\"modal-title\">T\u00e9rminos y Condiciones</div>\n      <button class=\"modal-close\" onclick=\"cerrarModal('modal-terminos')\">\u00d7</button>\n    </div>\n    <div style=\"font-size:12px;color:var(--text-muted);line-height:1.8;max-height:60vh;overflow-y:auto;padding-right:8px;\">\n      <p style=\"margin-bottom:12px;color:var(--text);font-size:11px;\">Versi\u00f3n 1.0 \u2014 Medell\u00edn, Colombia</p>\n\n      <p style=\"font-weight:600;color:var(--text);margin-bottom:6px;\">1. Objeto</p>\n      <p style=\"margin-bottom:12px;\">Clavo5 es una plataforma de gesti\u00f3n de cartera que facilita el registro y seguimiento de obligaciones en mora. Su objetivo es apoyar a las empresas en la recuperaci\u00f3n de cartera y promover la negociaci\u00f3n y el pago voluntario de deudas.</p>\n\n      <p style=\"font-weight:600;color:var(--text);margin-bottom:6px;\">2. Responsabilidad de las empresas usuarias</p>\n      <p style=\"margin-bottom:12px;\">La empresa que registra un reporte de mora declara bajo su responsabilidad que la informaci\u00f3n suministrada es ver\u00eddica, actualizada y corresponde a una obligaci\u00f3n real. Clavo5 act\u00faa como operador de datos y no verifica la veracidad de los reportes. La responsabilidad legal de cada reporte recae exclusivamente sobre la empresa que lo genera.</p>\n\n      <p style=\"font-weight:600;color:var(--text);margin-bottom:6px;\">3. Tratamiento de datos personales</p>\n      <p style=\"margin-bottom:12px;\">Clavo5 trata los datos personales conforme a la Ley 1581 de 2012 y el Decreto 1377 de 2013. Los datos registrados se usan exclusivamente para los fines de la plataforma. La empresa usuaria garantiza que cuenta con las autorizaciones necesarias para reportar la informaci\u00f3n de terceros.</p>\n\n      <p style=\"font-weight:600;color:var(--text);margin-bottom:6px;\">4. Derecho de correcci\u00f3n y actualizaci\u00f3n</p>\n      <p style=\"margin-bottom:12px;\">Toda persona que aparezca reportada tiene derecho a solicitar la correcci\u00f3n, actualizaci\u00f3n o eliminaci\u00f3n de su informaci\u00f3n a trav\u00e9s del mecanismo dispuesto en la plataforma o escribiendo a contacto@plataformac5.com. Clavo5 trasladar\u00e1 la solicitud a la empresa responsable del reporte en un plazo m\u00e1ximo de 5 d\u00edas h\u00e1biles.</p>\n\n      <p style=\"font-weight:600;color:var(--text);margin-bottom:6px;\">5. Limitaci\u00f3n de responsabilidad</p>\n      <p style=\"margin-bottom:12px;\">Clavo5 no es responsable por da\u00f1os derivados del uso indebido de la informaci\u00f3n por parte de las empresas usuarias, ni por la inexactitud de los datos reportados. La plataforma se reserva el derecho de suspender o eliminar reportes que violen estos t\u00e9rminos.</p>\n\n      <p style=\"font-weight:600;color:var(--text);margin-bottom:6px;\">6. Jurisdicci\u00f3n</p>\n      <p style=\"margin-bottom:12px;\">Cualquier controversia derivada del uso de esta plataforma se resolver\u00e1 conforme a las leyes de la Rep\u00fablica de Colombia, bajo la jurisdicci\u00f3n de los jueces competentes de la ciudad de Medell\u00edn.</p>\n\n      <p style=\"font-weight:600;color:var(--text);margin-bottom:6px;\">7. Contacto</p>\n      <p>Para cualquier consulta: contacto@plataformac5.com</p>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"aceptarTerminos()\" style=\"margin-top:18px;\">Acepto los t\u00e9rminos</button>\n    <button class=\"btn btn-ghost\" onclick=\"cerrarModal('modal-terminos')\">Cerrar</button>\n  </div>\n</div>\n\n<!-- MODAL SOLICITUD DE CORRECCI\u00d3N -->\n<div class=\"modal-overlay\" id=\"modal-correccion\">\n  <div class=\"modal-card\" style=\"max-width:440px;\">\n    <div class=\"modal-header\">\n      <div class=\"modal-title\">\ud83d\udccb Solicitar correcci\u00f3n</div>\n      <button class=\"modal-close\" onclick=\"cerrarModal('modal-correccion')\">\u00d7</button>\n    </div>\n    <input type=\"hidden\" id=\"cor-deuda-id\"/>\n    <input type=\"hidden\" id=\"cor-empresa-id\"/>\n    <div style=\"background:var(--surface2);border-radius:8px;padding:12px;margin-bottom:16px;font-size:13px;\" id=\"cor-info\"></div>\n    <div class=\"field\">\n      <label>Tu nombre completo *</label>\n      <input type=\"text\" id=\"cor-nombre\" placeholder=\"Nombre completo\"/>\n    </div>\n    <div class=\"field\">\n      <label>Tu celular *</label>\n      <div class=\"phone-wrap\"><div class=\"phone-prefix\">\ud83c\udde8\ud83c\uddf4 +57</div>\n        <input type=\"tel\" id=\"cor-celular\" placeholder=\"300 123 4567\" maxlength=\"10\" inputmode=\"numeric\" autocomplete=\"off\"/>\n      </div>\n    </div>\n    <div class=\"field\">\n      <label>Tipo de solicitud *</label>\n      <select id=\"cor-tipo\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\">\n        <option value=\"\">Selecciona...</option>\n        <option value=\"error_datos\">Error en mis datos (nombre o documento incorrecto)</option>\n        <option value=\"deuda_pagada\">La deuda ya fue pagada</option>\n        <option value=\"deuda_inexistente\">Esta deuda no existe o no me pertenece</option>\n        <option value=\"otro\">Otro motivo</option>\n      </select>\n    </div>\n    <div class=\"field\">\n      <label>Descripci\u00f3n *</label>\n      <input type=\"text\" id=\"cor-descripcion\" placeholder=\"Explica brevemente tu solicitud\"/>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"enviarCorreccion()\" id=\"btn-correccion\">Enviar solicitud</button>\n    <button class=\"btn btn-ghost\" onclick=\"cerrarModal('modal-correccion')\">Cancelar</button>\n    <div style=\"margin-top:12px;font-size:11px;color:var(--text-dim);text-align:center;\">Tu solicitud ser\u00e1 revisada por la empresa en un plazo de 5 d\u00edas h\u00e1biles.</div>\n  </div>\n</div>\n\n<!-- MODAL CARTA DE COBRO -->\n<div class=\"modal-overlay\" id=\"modal-carta-cobro\">\n  <div class=\"modal-card\" style=\"max-width:480px;\">\n    <div class=\"modal-header\">\n      <div class=\"modal-title\">Carta de cobro digital</div>\n      <button class=\"modal-close\" onclick=\"cerrarModal('modal-carta-cobro')\">x</button>\n    </div>\n    <div style=\"font-size:13px;color:var(--text-muted);margin-bottom:16px;line-height:1.5;\">\n      Selecciona los deudores. Cada envio tiene un costo de <strong style=\"color:#ffb347;\">$1.900</strong>.\n    </div>\n    <div id=\"carta-lista\" style=\"max-height:280px;overflow-y:auto;margin-bottom:16px;\"></div>\n    <div style=\"background:var(--surface2);border-radius:8px;padding:12px;margin-bottom:16px;font-size:13px;\">\n      <div style=\"display:flex;justify-content:space-between;\"><span style=\"color:var(--text-muted);\">Seleccionados:</span><span id=\"carta-count\" style=\"color:var(--text);font-weight:600;\">0</span></div>\n      <div style=\"display:flex;justify-content:space-between;margin-top:4px;\"><span style=\"color:var(--text-muted);\">Total:</span><span id=\"carta-total\" style=\"color:#ffb347;font-weight:700;\">$0</span></div>\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"enviarCartasCobro()\" id=\"btn-carta\" style=\"background:linear-gradient(135deg,#ffb347,#ff8c00);color:#1a0a00;\">Pagar y enviar cartas</button>\n    <button class=\"btn btn-ghost\" onclick=\"cerrarModal('modal-carta-cobro')\">Cancelar</button>\n  </div>\n</div>\n\n<!-- MODAL VERIFICACION MASIVA -->\n<div class=\"modal-overlay\" id=\"modal-masiva\">\n  <div class=\"modal-card\" style=\"max-width:500px;\">\n    <div class=\"modal-header\">\n      <div class=\"modal-title\">Verificacion masiva</div>\n      <button class=\"modal-close\" onclick=\"cerrarModal('modal-masiva')\">x</button>\n    </div>\n    <div style=\"font-size:13px;color:var(--text-muted);margin-bottom:16px;line-height:1.5;\">\n      Sube un archivo Excel o CSV con los numeros de documento. El sistema dira cuales estan reportados en Clavo5.\n    </div>\n    <div style=\"background:var(--surface2);border:2px dashed var(--border);border-radius:12px;padding:30px;text-align:center;margin-bottom:16px;\">\n      <div style=\"font-size:32px;margin-bottom:8px;\">\ud83d\udcc1</div>\n      <div style=\"font-size:13px;color:var(--text-muted);margin-bottom:12px;\">Selecciona tu archivo Excel o CSV</div>\n      <input type=\"file\" id=\"masiva-file\" accept=\".xlsx,.xls,.csv\" style=\"display:none;\" onchange=\"procesarArchivoMasivo(this)\"/>\n      <button onclick=\"document.getElementById('masiva-file').click()\" style=\"background:var(--surface);border:1px solid var(--border);color:var(--text);border-radius:8px;padding:8px 16px;font-size:13px;cursor:pointer;font-family:'DM Sans',sans-serif;\">Seleccionar archivo</button>\n    </div>\n    <div id=\"masiva-preview\" style=\"display:none;margin-bottom:16px;\"></div>\n    <div style=\"background:rgba(0,153,255,.06);border:1px solid rgba(0,153,255,.15);border-radius:8px;padding:12px;font-size:11px;color:var(--text-muted);line-height:1.6;\">\n      El archivo debe tener una columna con los numeros de documento. Maximo 1.000 registros.\n    </div>\n    <button class=\"btn btn-primary\" onclick=\"ejecutarVerificacionMasiva()\" id=\"btn-masiva\" style=\"margin-top:16px;\" disabled>Verificar documentos</button>\n    <button class=\"btn btn-ghost\" onclick=\"cerrarModal('modal-masiva')\">Cancelar</button>\n  </div>\n</div>\n\n<!-- MODAL PLANES -->\n<div class=\"modal-overlay\" id=\"modal-planes\">\n  <div class=\"modal-card\" style=\"max-width:700px;\">\n    <div class=\"modal-header\">\n      <div class=\"modal-title\">Planes Clavo5</div>\n      <button class=\"modal-close\" onclick=\"cerrarModal('modal-planes')\">x</button>\n    </div>\n    <div style=\"font-size:13px;color:var(--text-muted);margin-bottom:16px;text-align:center;\">Potencia tu gestion de cartera</div>\n\n    <div style=\"font-family:Syne,sans-serif;font-weight:700;font-size:13px;color:var(--text-muted);margin-bottom:10px;letter-spacing:.05em;\">PLANES MENSUALES</div>\n    <div style=\"display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:10px;margin-bottom:20px;\">\n\n      <div style=\"background:var(--surface2);border:1px solid var(--border);border-radius:12px;padding:14px;text-align:center;\">\n        <div style=\"font-size:11px;text-transform:uppercase;color:var(--text-muted);margin-bottom:6px;\">Gratuito</div>\n        <div style=\"font-family:Syne,sans-serif;font-weight:800;font-size:22px;color:var(--text);\">$0</div>\n        <div style=\"font-size:11px;color:var(--text-muted);margin-bottom:10px;\">para siempre</div>\n        <div style=\"font-size:11px;color:var(--text-muted);text-align:left;line-height:1.9;\">\n          \u2713 5 consultas/mes<br>\u2713 Reportar morosos<br>\u2717 Notif. negociacion<br>\u2717 Exportar Excel<br>\u2717 Datos del deudor<br>\u2717 Cartas de cobro\n        </div>\n        <div style=\"margin-top:10px;padding:6px;background:rgba(0,212,170,.1);border-radius:8px;font-size:11px;color:var(--accent);\">Plan actual</div>\n      </div>\n\n      <div style=\"background:var(--surface2);border:1px solid rgba(0,153,255,.4);border-radius:12px;padding:14px;text-align:center;\">\n        <div style=\"font-size:11px;text-transform:uppercase;color:var(--accent2);margin-bottom:6px;\">Estandar</div>\n        <div style=\"font-family:Syne,sans-serif;font-weight:800;font-size:22px;color:var(--text);\">$9.900</div>\n        <div style=\"font-size:11px;color:var(--text-muted);margin-bottom:10px;\">por mes</div>\n        <div style=\"font-size:11px;color:var(--text-muted);text-align:left;line-height:1.9;\">\n          \u2713 50 consultas/mes<br>\u2713 Reportar morosos<br>\u2713 Notif. negociacion<br>\u2713 Exportar Excel<br>\u2713 Estadisticas<br>\u2717 Datos del deudor\n        </div>\n        <button onclick=\"pagarConBold('estandar',9900)\" style=\"margin-top:10px;width:100%;background:linear-gradient(135deg,var(--accent2),#0055ff);color:#fff;border:none;border-radius:8px;padding:8px;font-size:12px;font-weight:600;cursor:pointer;font-family:Syne,sans-serif;\">Suscribirme</button>\n      </div>\n\n      <div style=\"background:var(--surface2);border:2px solid var(--accent);border-radius:12px;padding:14px;text-align:center;position:relative;\">\n        <div style=\"position:absolute;top:-10px;left:50%;transform:translateX(-50%);background:var(--accent);color:#001a14;font-size:10px;font-weight:700;padding:3px 8px;border-radius:20px;font-family:Syne,sans-serif;white-space:nowrap;\">MAS POPULAR</div>\n        <div style=\"font-size:11px;text-transform:uppercase;color:var(--accent);margin-bottom:6px;\">Premium</div>\n        <div style=\"font-family:Syne,sans-serif;font-weight:800;font-size:22px;color:var(--text);\">$19.900</div>\n        <div style=\"font-size:11px;color:var(--text-muted);margin-bottom:10px;\">por mes</div>\n        <div style=\"font-size:11px;color:var(--text-muted);text-align:left;line-height:1.9;\">\n          \u2713 200 consultas/mes<br>\u2713 Reportar morosos<br>\u2713 Notif. negociacion<br>\u2713 Exportar Excel<br>\u2713 Datos del deudor<br>\u2713 5 cartas/mes\n        </div>\n        <button onclick=\"pagarConBold('premium',19900)\" style=\"margin-top:10px;width:100%;background:linear-gradient(135deg,var(--accent),#00b894);color:#001a14;border:none;border-radius:8px;padding:8px;font-size:12px;font-weight:600;cursor:pointer;font-family:Syne,sans-serif;\">Suscribirme</button>\n      </div>\n\n    </div>\n\n    <div style=\"font-family:Syne,sans-serif;font-weight:700;font-size:13px;color:var(--text-muted);margin-bottom:10px;letter-spacing:.05em;\">SERVICIOS ADICIONALES</div>\n    <div style=\"display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:10px;margin-bottom:16px;\">\n\n      <div style=\"background:var(--surface2);border:1px solid rgba(255,179,71,.3);border-radius:12px;padding:14px;\">\n        <div style=\"font-size:20px;margin-bottom:6px;\">\ud83d\udce8</div>\n        <div style=\"font-family:Syne,sans-serif;font-weight:700;font-size:13px;color:var(--text);margin-bottom:4px;\">Carta de cobro digital</div>\n        <div style=\"font-size:11px;color:var(--text-muted);margin-bottom:10px;line-height:1.5;\">SMS al deudor informando que esta reportado e invitandolo a negociar.</div>\n        <div style=\"font-family:Syne,sans-serif;font-weight:700;font-size:18px;color:#ffb347;margin-bottom:10px;\">$1.900 <span style=\"font-size:11px;font-weight:400;color:var(--text-muted);\">por envio</span></div>\n        <button onclick=\"cerrarModal('modal-planes');abrirCartaCobro()\" style=\"width:100%;background:rgba(255,179,71,.15);border:1px solid rgba(255,179,71,.3);color:#ffb347;border-radius:8px;padding:8px;font-size:12px;font-weight:600;cursor:pointer;font-family:Syne,sans-serif;\">Enviar cartas</button>\n      </div>\n\n      <div style=\"background:var(--surface2);border:1px solid rgba(0,153,255,.3);border-radius:12px;padding:14px;\">\n        <div style=\"font-size:20px;margin-bottom:6px;\">\ud83d\udcca</div>\n        <div style=\"font-family:Syne,sans-serif;font-weight:700;font-size:13px;color:var(--text);margin-bottom:4px;\">Verificacion masiva</div>\n        <div style=\"font-size:11px;color:var(--text-muted);margin-bottom:10px;line-height:1.5;\">Sube un Excel y verifica cuales documentos estan reportados. Hasta 1.000 registros.</div>\n        <div style=\"font-family:Syne,sans-serif;font-weight:700;font-size:18px;color:var(--accent2);margin-bottom:10px;\">$29.900 <span style=\"font-size:11px;font-weight:400;color:var(--text-muted);\">/mes</span></div>\n        <button onclick=\"cerrarModal('modal-planes');document.getElementById('modal-masiva').style.display='flex'\" style=\"width:100%;background:rgba(0,153,255,.15);border:1px solid rgba(0,153,255,.3);color:var(--accent2);border-radius:8px;padding:8px;font-size:12px;font-weight:600;cursor:pointer;font-family:Syne,sans-serif;\">Activar</button>\n      </div>\n\n    </div>\n\n    <div style=\"background:rgba(0,153,255,.06);border:1px solid rgba(0,153,255,.15);border-radius:10px;padding:12px;font-size:11px;color:var(--text-muted);text-align:center;\">\n      Pagos seguros por <strong style=\"color:var(--text);\">Bold</strong> \u2014 Tarjetas, PSE y Nequi. Cancela cuando quieras.\n    </div>\n  </div>\n</div>\n\n<!-- MODAL SOLICITUDES RECIBIDAS <!-- MODAL SOLICITUDES RECIBIDAS -->\n<div class=\"modal-overlay\" id=\"modal-solicitudes\">\n  <div class=\"modal-card\" style=\"max-width:600px;\">\n    <div class=\"modal-header\">\n      <div class=\"modal-title\">\ud83d\udccb Solicitudes de correcci\u00f3n</div>\n      <button class=\"modal-close\" onclick=\"cerrarModal('modal-solicitudes')\">\u00d7</button>\n    </div>\n    <div id=\"solicitudes-lista\" style=\"max-height:60vh;overflow-y:auto;\"></div>\n  </div>\n</div>\n\n<!-- MODAL NEGOCIAR DEUDA -->\n<div class=\"modal-overlay\" id=\"modal-negociar\">\n  <div class=\"modal-card\" style=\"max-width:420px;\">\n    <div class=\"modal-header\">\n      <div class=\"modal-title\">\ud83e\udd1d Negociar deuda</div>\n      <button class=\"modal-close\" onclick=\"cerrarModal('modal-negociar')\">\u00d7</button>\n    </div>\n    <div id=\"neg-info\" style=\"background:var(--surface2);border-radius:8px;padding:12px;margin-bottom:18px;font-size:13px;color:var(--text-muted);\"></div>\n    <div class=\"card-sub\" style=\"margin-bottom:18px;\">Deja tus datos y nos comunicaremos con la empresa para iniciar el proceso de negociaci\u00f3n.</div>\n    <div class=\"field\"><label>Tu nombre completo *</label><input type=\"text\" id=\"neg-nombre\" placeholder=\"Ej: Juan P\u00e9rez\"/></div>\n    <div class=\"field\"><label>Tu celular (WhatsApp) *</label>\n      <div class=\"phone-wrap\"><div class=\"phone-prefix\">\ud83c\udde8\ud83c\uddf4 +57</div><input type=\"tel\" id=\"neg-celular\" placeholder=\"300 123 4567\" maxlength=\"10\" inputmode=\"numeric\" autocomplete=\"off\"/></div>\n    </div>\n    <div class=\"field\"><label>Mensaje (opcional)</label><input type=\"text\" id=\"neg-mensaje\" placeholder=\"Ej: Quiero pagar en cuotas\"/></div>\n    <button class=\"btn btn-primary\" onclick=\"enviarNegociacion()\" id=\"btn-neg\">Enviar solicitud</button>\n    <button class=\"btn btn-ghost\" onclick=\"cerrarModal('modal-negociar')\">Cancelar</button>\n    <div style=\"margin-top:14px;font-size:11px;color:var(--text-dim);text-align:center;\">Tu informaci\u00f3n ser\u00e1 compartida \u00fanicamente con la empresa acreedora.</div>\n  </div>\n</div>\n\n<!-- MODAL ELIMINAR -->\n<div class=\"modal-overlay\" id=\"modal-delete\">\n  <div class=\"modal-card\" style=\"max-width:400px;\">\n    <div class=\"modal-header\">\n      <div class=\"modal-title\">\ud83d\uddd1 Eliminar reporte</div>\n      <button class=\"modal-close\" onclick=\"cerrarModal('modal-delete')\">\u00d7</button>\n    </div>\n    <p id=\"delete-desc\" style=\"color:var(--text-muted);font-size:14px;margin-bottom:18px;line-height:1.5;\"></p>\n    <div class=\"field\">\n      <label>\u00bfPor qu\u00e9 eliminas este reporte? *</label>\n      <select id=\"motivo-eliminacion\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:var(--radius-sm);padding:13px 16px;color:var(--text);font-family:'DM Sans',sans-serif;font-size:14px;outline:none;\">\n        <option value=\"\">Selecciona un motivo...</option>\n        <option value=\"pagada\">El deudor pag\u00f3 la deuda</option>\n        <option value=\"error_registro\">Error en el registro</option>\n        <option value=\"otro\">Otro motivo</option>\n      </select>\n    </div>\n    <div class=\"field\" id=\"otro-motivo-wrap\" style=\"display:none;\">\n      <label>Especifica el motivo</label>\n      <input type=\"text\" id=\"otro-motivo\" placeholder=\"Describe el motivo...\"/>\n    </div>\n    <button class=\"btn\" style=\"background:var(--danger);color:#fff;margin-top:8px;\" onclick=\"confirmarEliminar()\">Eliminar reporte</button>\n    <button class=\"btn btn-ghost\" onclick=\"cerrarModal('modal-delete')\">Cancelar</button>\n  </div>\n</div>\n\n<div class=\"toast\" id=\"toast\"></div>\n\n<script>\nwindow.onerror = function(msg, src, line, col, err) {\n  console.error('ERROR l\u00ednea ' + line + ': ' + msg);\n  return false;\n};\nconst { createClient } = supabase;\nconst supa = createClient(\n  'https://wkonrahcswzxxkwvewbp.supabase.co',\n  'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Indrb25yYWhjc3d6eHhrd3Zld2JwIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzgwMjU3NjUsImV4cCI6MjA5MzYwMTc2NX0.sjMMYT7inRQT7KDbwr3eD5UEhFnh2rWrovyDfhGavKA'\n);\n\nlet state = { empresa: null, regData: {}, editDatosAnt: null };\n\n// Sesion persistente solo al cargar\n(async () => {\n  try { await cargarTiposDocVerificacion(); } catch(e) { console.warn('Error cargando tipos doc:', e); }\n  try {\n    const { data: { session } } = await supa.auth.getSession();\n    if (session) {\n      const { data: emp } = await supa.from('Tbl_Empresa').select('*').eq('auth_user_id', session.user.id).maybeSingle();\n      if (emp) { state.empresa = emp; abrirDashboard(); }\n      else { await supa.auth.signOut(); showScreen('welcome'); }\n    } else { showScreen('welcome'); }\n  } catch(e) { console.warn('Error verificando sesion:', e); showScreen('welcome'); }\n})();\n\nfunction showScreen(id) {\n  document.querySelectorAll('.screen').forEach(function(s){ s.classList.remove('active'); });\n  document.getElementById(id).classList.add('active');\n  window.scrollTo(0,0);\n}\n\nlet toastTimer;\nfunction toast(msg, type) {\n  type = type || 'info';\n  const t = document.getElementById('toast');\n  t.textContent = msg; t.className = 'toast show ' + type;\n  clearTimeout(toastTimer);\n  toastTimer = setTimeout(function(){ t.classList.remove('show'); }, 4000);\n}\n\nfunction togglePass(id, btn) {\n  const inp = document.getElementById(id);\n  inp.type = inp.type === 'password' ? 'text' : 'password';\n  btn.textContent = inp.type === 'password' ? 'ver' : 'ocultar';\n}\n\nfunction otpNext(el, prefix, idx) {\n  el.value = el.value.replace(/\\D/,'');\n  if (el.value && idx < 5) document.getElementById(prefix+(idx+1)).focus();\n}\n\nfunction getOTP(prefix) {\n  return [0,1,2,3,4,5].map(function(i){ return document.getElementById(prefix+i).value; }).join('');\n}\n\nfunction clearOTP(prefix) {\n  [0,1,2,3,4,5].forEach(function(i){ document.getElementById(prefix+i).value = ''; });\n  document.getElementById(prefix+'0').focus();\n}\n\ndocument.querySelectorAll('.otp-box').forEach(function(box) {\n  box.addEventListener('keydown', function(e) {\n    if (e.key === 'Backspace' && !box.value) {\n      const prefix = box.id.startsWith('ro') ? 'ro' : 'o';\n      const i = parseInt(box.id.replace(prefix,''));\n      if (i > 0) document.getElementById(prefix+(i-1)).focus();\n    }\n  });\n});\n\nasync function hacerLogin() {\n  const celular = document.getElementById('login-celular').value.trim().replace(/\\s/g,'');\n  const pass    = document.getElementById('login-pass').value;\n  if (!celular || celular.length < 10) { toast('Ingresa un celular valido de 10 digitos', 'error'); return; }\n  if (!pass) { toast('Ingresa tu contrasena', 'error'); return; }\n\n  const btn = document.getElementById('btn-login');\n  btn.disabled = true; btn.textContent = 'Verificando...';\n\n  try {\n    await supa.auth.signOut();\n\n    // Intentar con ambos dominios de email\n    var loginOk = false;\n    var userData = null;\n    var emails = [celular + '@plataformac5.com', celular + '@clavo5.com'];\n\n    for (var i = 0; i < emails.length; i++) {\n      var { data, error } = await supa.auth.signInWithPassword({ email: emails[i], password: pass });\n      if (!error && data && data.user) {\n        loginOk = true;\n        userData = data;\n        break;\n      }\n    }\n\n    if (!loginOk) { toast('Celular o contrasena incorrectos', 'error'); return; }\n\n    btn.textContent = 'Cargando...';\n    const { data: emp, error: empErr } = await supa\n      .from('Tbl_Empresa').select('*').eq('auth_user_id', userData.user.id).maybeSingle();\n\n    if (empErr || !emp) { toast('No se encontro empresa para este usuario', 'error'); await supa.auth.signOut(); return; }\n\n    state.empresa = emp;\n    abrirDashboard();\n  } catch(e) {\n    toast('Error: ' + e.message, 'error');\n  } finally {\n    btn.disabled = false; btn.textContent = 'Ingresar';\n  }\n}\n\nfunction regPaso1() {\n  const nombre      = document.getElementById('reg-nombre').value.trim();\n  const celular     = document.getElementById('reg-celular').value.trim().replace(/\\s/g,'');\n  const responsable = document.getElementById('reg-responsable').value.trim();\n  if (!nombre) { toast('El nombre de la empresa es obligatorio', 'error'); return; }\n  if (!celular || celular.length < 10) { toast('Ingresa un celular valido de 10 digitos', 'error'); return; }\n  state.regData = { nombre: nombre, celular: celular, responsable: responsable };\n  showScreen('reg-step2');\n}\n\nasync function regPaso2() {\n  const pass  = document.getElementById('reg-pass').value;\n  const pass2 = document.getElementById('reg-pass2').value;\n  if (!pass || pass.length < 8) { toast('La contrasena debe tener minimo 8 caracteres', 'error'); return; }\n  if (pass !== pass2) { toast('Las contrasenas no coinciden', 'error'); return; }\n  if (!document.getElementById('reg-terminos').checked) { toast('Debes aceptar los terminos y condiciones', 'error'); return; }\n\n  state.regData.pass = pass;\n\n  // Generar OTP\n  const otp = Math.floor(100000 + Math.random() * 900000).toString();\n  state.regData.otp = otp;\n\n  const btn = document.getElementById('btn-reg2');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Enviando codigo...';\n\n  // Intentar enviar SMS real\n  try {\n    const res = await fetch('/functions/enviar-sms', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        celular: state.regData.celular,\n        mensaje: 'Plataforma C5 \u2014 Tu codigo de verificacion es: ' + otp + '. Valido por 10 minutos.'\n      })\n    });\n    const data = await res.json();\n    if (data.ok) {\n      // SMS enviado exitosamente \u2014 ocultar caja demo\n      document.getElementById('otp-demo-box').style.display = 'none';\n      document.getElementById('reg-otp-desc').textContent =\n        'Ingresa el codigo de 6 digitos enviado por SMS al +57 ' + state.regData.celular.slice(0,3) + '***' + state.regData.celular.slice(-2);\n    } else {\n      throw new Error('SMS fallido');\n    }\n  } catch(e) {\n    // Si falla el SMS, mostrar en pantalla (modo demo)\n    document.getElementById('otp-demo-code').textContent = otp;\n    document.getElementById('otp-demo-cel').textContent  = state.regData.celular;\n    document.getElementById('otp-demo-box').style.display = 'block';\n    document.getElementById('reg-otp-desc').textContent =\n      'Codigo generado (modo demo) para +57 ' + state.regData.celular.slice(0,3) + '***' + state.regData.celular.slice(-2);\n  }\n\n  // Limpiar cajas OTP\n  [0,1,2,3,4,5].forEach(function(i){ document.getElementById('ro'+i).value = ''; });\n\n  btn.disabled = false; btn.textContent = 'Continuar \u2192';\n  showScreen('reg-step3');\n}\n\nfunction reenviarOTP() {\n  const otp = Math.floor(100000 + Math.random() * 900000).toString();\n  state.regData.otp = otp;\n  document.getElementById('otp-demo-code').textContent = otp;\n  document.getElementById('otp-demo-box').style.display = 'block';\n  toast('Nuevo codigo generado', 'info');\n}\n\nasync function regVerificarOTP() {\n  const codigo = getOTP('ro');\n  if (codigo.length < 6) { toast('Ingresa los 6 digitos del codigo', 'error'); return; }\n  if (codigo !== state.regData.otp) { toast('Codigo incorrecto. Intentalo de nuevo.', 'error'); return; }\n\n  const email = state.regData.celular + '@plataformac5.com';\n  const pass  = state.regData.pass;\n\n  const btn = document.getElementById('btn-reg3');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Creando cuenta...';\n\n  // Crear usuario en Supabase Auth\n  const { data: authData, error: authError } = await supa.auth.signUp({ email: email, password: pass });\n\n  if (authError) {\n    const msg = authError.message.includes('already') ? 'Este celular ya esta registrado. Inicia sesion.' : authError.message;\n    toast(msg, 'error');\n    btn.disabled = false; btn.textContent = 'Verificar y crear cuenta';\n    return;\n  }\n\n  const userId = authData.user ? authData.user.id : null;\n  if (!userId) {\n    toast('Error al crear usuario. Intenta de nuevo.', 'error');\n    btn.disabled = false; btn.textContent = 'Verificar y crear cuenta';\n    return;\n  }\n\n  // Login inmediato para tener sesi\u00f3n activa antes de insertar\n  await supa.auth.signInWithPassword({ email: email, password: pass });\n\n  // Guardar empresa directo en Supabase con anon key (RLS protege)\n  btn.textContent = 'Creando cuenta...';\n  const empPayload = { Nombre_Empresa: state.regData.nombre, Celular: state.regData.celular, auth_user_id: userId };\n  if (state.regData.responsable) empPayload['Nombre del responsable'] = state.regData.responsable;\n\n  const { data: empData, error: empError } = await supa.from('Tbl_Empresa').insert(empPayload).select().single();\n\n  btn.disabled = false; btn.textContent = 'Verificar y crear cuenta';\n\n  if (empError) {\n    toast('Error al guardar empresa: ' + empError.message, 'error');\n    return;\n  }\n\n  state.empresa = empData;\n  toast('Cuenta creada exitosamente!', 'success');\n  setTimeout(function(){ abrirDashboard(); }, 700);\n}\n\n\nfunction abrirDashboard() {\n  showScreen('dashboard');\n  const emp = state.empresa;\n  document.getElementById('dash-empresa-nombre').textContent = emp.Nombre_Empresa || 'Empresa';\n  document.getElementById('dash-responsable').textContent   = emp['Nombre del responsable'] || emp.Nombre_Empresa;\n  document.getElementById('dash-info').textContent          = 'Celular: +57 ' + (emp.Celular || '-');\n  cargarMorosos();\n}\n\nasync function cargarMorosos() {\n  const tbody = document.getElementById('morosos-tbody');\n  tbody.innerHTML = '<tr class=\"loading-row\"><td colspan=\"9\"><span class=\"spinner\"></span> Cargando...</td></tr>';\n\n  const { data: deudas, error } = await supa\n    .from('Fac_deudas').select('*')\n    .eq('Id_empresa', state.empresa.id)\n    .order('created_at', { ascending: false });\n\n  if (error) { tbody.innerHTML = '<tr><td colspan=\"9\" style=\"text-align:center;padding:30px;color:var(--danger)\">Error: '+error.message+'</td></tr>'; return; }\n\n  if (!deudas || deudas.length === 0) {\n    tbody.innerHTML = '<tr><td colspan=\"9\"><div class=\"empty-state\"><div class=\"empty-icon\">\ud83d\udccb</div><div class=\"empty-text\">No hay personas morosas reportadas.<br>Usa + Reportar moroso para agregar.</div></div></td></tr>';\n    document.getElementById('stat-total').textContent = '$0';\n    document.getElementById('stat-count').textContent = '0';\n    return;\n  }\n\n  const personaIds = deudas.map(function(d){ return d.Id_persona; });\n\n  // Traer documentos del maestro\n  const { data: personas } = await supa\n    .from('Tbl_Persona')\n    .select('id, Nro_documento')\n    .in('id', personaIds);\n\n  // Traer nombre, depto y municipio desde Tbl_Persona_Empresa (por empresa)\n  const { data: persEmpresas } = await supa\n    .from('Tbl_Persona_Empresa')\n    .select('persona_id, nombre_empresa, id_departamento, id_municipio')\n    .eq('empresa_id', state.empresa.id)\n    .in('persona_id', personaIds);\n\n  // Cargar nombres de departamentos y municipios\n  const deptoIds = [...new Set((persEmpresas||[]).map(function(pe){ return pe.id_departamento; }).filter(Boolean))];\n  const mpioIds  = [...new Set((persEmpresas||[]).map(function(pe){ return pe.id_municipio; }).filter(Boolean))];\n  const { data: deptos } = deptoIds.length ? await supa.from('Tbl_Departamento').select('id, Nombre_Departamento').in('id', deptoIds) : { data: [] };\n  const { data: mpios  } = mpioIds.length  ? await supa.from('Tbl_municipios').select('id, Nombre_mpio').in('id', mpioIds)           : { data: [] };\n\n  const personaMap = {};\n  (personas||[]).forEach(function(p){ personaMap[p.id] = { doc: p.Nro_documento }; });\n  (persEmpresas||[]).forEach(function(pe){\n    if (personaMap[pe.persona_id]) {\n      personaMap[pe.persona_id].nombre  = pe.nombre_empresa;\n      personaMap[pe.persona_id].deptoId = pe.id_departamento;\n      personaMap[pe.persona_id].mpioId  = pe.id_municipio;\n    }\n  });\n  const deptoMap = {}; (deptos||[]).forEach(function(d){ deptoMap[d.id] = d.Nombre_Departamento; });\n  const mpioMap  = {}; (mpios||[]).forEach(function(m){ mpioMap[m.id]  = m.Nombre_mpio; });\n\n  let total = 0;\n  morososData = [];\n\n  deudas.forEach(function(d) {\n    total += parseFloat(d.Valor_total_deuda) || 0;\n    const p = personaMap[d.Id_persona] || {};\n    d._nombre = p.nombre || '-';\n    d._doc    = p.doc    || '-';\n    d._depto  = deptoMap[p.deptoId] || '-';\n    d._mpio   = mpioMap[p.mpioId]   || '-';\n    d._valor  = '$' + parseFloat(d.Valor_total_deuda).toLocaleString('es-CO',{maximumFractionDigits:0});\n    d._fecha  = d.Fecha_Vencimiento_deuda ? new Date(d.Fecha_Vencimiento_deuda+'T00:00:00').toLocaleDateString('es-CO',{day:'2-digit',month:'short',year:'numeric'}) : '-';\n    morososData.push(d);\n  });\n\n  renderMorosos(morososData);\n  document.getElementById('stat-total').textContent = '$' + total.toLocaleString('es-CO',{maximumFractionDigits:0});\n  document.getElementById('stat-count').textContent = deudas.length;\n}\n\nasync function abrirModalNuevo() {\n  // Limpiar campos\n  ['m-documento','m-nombre','m-valor','m-obs'].forEach(function(id){ document.getElementById(id).value=''; });\n  document.getElementById('m-tipo-doc').value = '';\n  document.getElementById('m-depto').value = '';\n  document.getElementById('m-celular-deudor').value = '';\n  document.getElementById('m-enviar-sms').checked = false;\n  document.getElementById('sms-notif-wrap').style.display = 'none';\n  document.getElementById('m-mpio').innerHTML = '<option value=\"\">Selecciona municipio...</option>';\n  // Resetear selectores de fecha\n  document.getElementById('m-fecha-dia').value = '';\n  document.getElementById('m-fecha-mes').value = '';\n  document.getElementById('m-fecha-anio').value = '';\n  inicializarSelectoresFecha();\n\n  // Cargar tipos de documento\n  const { data: tipos } = await supa.from('Tbl_tipo_documento').select('id, Tipo_documento, Descr_tipo_documento').order('Tipo_documento');\n  const selTipo = document.getElementById('m-tipo-doc');\n  selTipo.innerHTML = '<option value=\"\">Selecciona...</option>';\n  if (tipos) tipos.forEach(function(t){\n    selTipo.innerHTML += '<option value=\"'+t.id+'\">'+t.Tipo_documento+' - '+t.Descr_tipo_documento+'</option>';\n  });\n\n  // Cargar departamentos\n  const { data: deptos } = await supa.from('Tbl_Departamento').select('id, Nombre_Departamento, cod_Departamento').order('Nombre_Departamento');\n  const selDepto = document.getElementById('m-depto');\n  selDepto.innerHTML = '<option value=\"\">Selecciona departamento...</option>';\n  if (deptos) deptos.forEach(function(d){\n    const opt = document.createElement('option');\n    opt.value = d.id;\n    opt.textContent = d.Nombre_Departamento;\n    opt.dataset.cod = d.cod_Departamento;\n    selDepto.appendChild(opt);\n  });\n\n  document.getElementById('modal-nuevo').style.display='flex';\n}\n\nasync function cargarMunicipios() {\n  const selDepto = document.getElementById('m-depto');\n  const selMpio  = document.getElementById('m-mpio');\n  const opt = selDepto.options[selDepto.selectedIndex];\n  const codDepto = opt ? opt.dataset.cod : null;\n\n  selMpio.innerHTML = '<option value=\"\">Cargando...</option>';\n\n  if (!codDepto) {\n    selMpio.innerHTML = '<option value=\"\">Selecciona municipio...</option>';\n    return;\n  }\n\n  const { data: mpios } = await supa\n    .from('Tbl_municipios')\n    .select('id, Nombre_mpio')\n    .eq('Cod_departamento', codDepto)\n    .order('Nombre_mpio');\n\n  selMpio.innerHTML = '<option value=\"\">Selecciona municipio...</option>';\n  if (mpios) mpios.forEach(function(m){\n    selMpio.innerHTML += '<option value=\"'+m.id+'\">'+m.Nombre_mpio+'</option>';\n  });\n}\n\nfunction toggleSMScheck() {\n  const cel = document.getElementById('m-celular-deudor').value.trim();\n  document.getElementById('sms-notif-wrap').style.display = cel.length >= 10 ? 'block' : 'none';\n  if (cel.length < 10) document.getElementById('m-enviar-sms').checked = false;\n}\n\nfunction formatearMiles(input) {\n  var raw = input.value.replace(/\\D/g, '');\n  if (raw) input.value = parseInt(raw).toLocaleString('es-CO');\n  else input.value = '';\n}\n\nfunction cerrarModal(id) {\n  document.getElementById(id).style.display='none';\n  if (id === 'modal-nuevo') {\n    personaEncontrada = null;\n    window._personasEncontradas = null;\n  }\n}\n\nasync function guardarMoroso() {\n  const tipoDoc   = document.getElementById('m-tipo-doc').value;\n  const documento = document.getElementById('m-documento').value.trim();\n  const nombre    = document.getElementById('m-nombre').value.trim();\n  const deptoId   = document.getElementById('m-depto').value;\n  const mpioId    = document.getElementById('m-mpio').value;\n  const valorRaw = document.getElementById('m-valor').value.replace(/\\./g,'').replace(/,/g,'').trim();\n  const valor    = valorRaw;\n  const fecha     = getFechaFromSelectors('m');\n  const obs       = document.getElementById('m-obs').value.trim();\n  const celularDeudor = document.getElementById('m-celular-deudor').value.trim().replace(/\\s/g,'');\n  const enviarSMS    = document.getElementById('m-enviar-sms').checked && celularDeudor.length >= 10;\n\n  if (!tipoDoc)   { toast('Selecciona el tipo de documento', 'error'); return; }\n  if (!documento) { toast('El numero de documento es obligatorio', 'error'); return; }\n  if (!nombre)    { toast('El nombre es obligatorio', 'error'); return; }\n  if (!deptoId)   { toast('Selecciona el departamento', 'error'); return; }\n  if (!mpioId)    { toast('Selecciona el municipio', 'error'); return; }\n  if (!valor || parseFloat(valor) <= 0) { toast('Ingresa un valor valido', 'error'); return; }\n  if (!fecha)     { toast('La fecha de vencimiento es obligatoria', 'error'); return; }\n  if (!validarFecha60Dias(fecha)) { toast('La deuda debe tener m\u00ednimo 2 meses de antig\u00fcedad', 'error'); return; }\n\n  const btn = document.getElementById('btn-guardar');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Guardando...';\n\n  try {\n    let personaId;\n\n    // Buscar si ya existe en el maestro por documento\n    const { data: maestro } = await supa.from('Tbl_Persona')\n      .select('id')\n      .eq('Nro_documento', documento)\n      .eq('Id_tp_documento', parseInt(tipoDoc))\n      .maybeSingle();\n\n    if (maestro) {\n      // Ya existe en el maestro \u2014 reutilizar\n      personaId = maestro.id;\n    } else {\n      // Crear en el maestro (solo documento y tipo \u2014 sin nombre)\n      const { data: nueva, error: errP } = await supa.from('Tbl_Persona').insert({\n        Nro_documento: documento,\n        Id_tp_documento: parseInt(tipoDoc),\n        Nombre_persona: nombre  // nombre inicial como referencia\n      }).select().single();\n      if (errP) throw new Error(errP.message);\n      personaId = nueva.id;\n    }\n\n    // Guardar o actualizar en Tbl_Persona_Empresa (nombre y ubicaci\u00f3n por empresa)\n    const { error: errPE } = await supa.from('Tbl_Persona_Empresa').upsert({\n      persona_id: personaId,\n      empresa_id: state.empresa.id,\n      nombre_empresa: nombre,\n      id_departamento: parseInt(deptoId),\n      id_municipio: parseInt(mpioId)\n    }, { onConflict: 'persona_id,empresa_id' });\n    if (errPE) throw new Error(errPE.message);\n\n    // Crear la deuda\n    const { error: errD } = await supa.from('Fac_deudas').insert({\n      Id_persona: personaId,\n      Id_empresa: state.empresa.id,\n      Valor_total_deuda: parseFloat(valor),\n      Fecha_Vencimiento_deuda: fecha,\n      Observacion: obs || null,\n      celular_deudor: celularDeudor || null\n    });\n    if (errD) throw new Error(errD.message);\n\n    // Enviar SMS si fue marcado\n    if (enviarSMS) {\n      try {\n        const { data: nuevaDeuda } = await supa.from('Fac_deudas').select('id').eq('Id_persona', personaId).eq('Id_empresa', state.empresa.id).order('created_at', { ascending: false }).limit(1).single();\n        const msgSMS = 'Fuiste reportado en Plataforma C5 por '\n          + state.empresa.Nombre_Empresa\n          + ' con una obligacion pendiente de $'\n          + parseFloat(valorRaw).toLocaleString('es-CO', { maximumFractionDigits: 0 })\n          + '. Consulta tu estado en plataformac5.com';\n\n        const resSMS = await fetch('/functions/enviar-sms', {\n          method: 'POST',\n          headers: { 'Content-Type': 'application/json' },\n          body: JSON.stringify({ celular: celularDeudor, mensaje: msgSMS })\n        });\n\n        if (resSMS.ok) {\n          if (nuevaDeuda) {\n            await supa.from('Fac_deudas').update({ sms_notificacion_enviado: true }).eq('id', nuevaDeuda.id);\n          }\n          toast('\u2705 Moroso registrado y SMS enviado', 'success');\n        } else {\n          toast('Moroso registrado. El SMS no pudo enviarse.', 'info');\n        }\n      } catch(eSMS) {\n        toast('Moroso registrado. Error al enviar SMS.', 'info');\n      }\n    } else {\n      toast('Moroso registrado exitosamente', 'success');\n    }\n    await registrarAuditoria('CREACION', 'Fac_deudas', personaId,\n      null, { nombre: nombre, documento: documento, valor: valorRaw, fecha: fecha, sms: enviarSMS });\n\n    cerrarModal('modal-nuevo');\n    cargarMorosos();\n\n  } catch(e) {\n    toast('Error: ' + e.message, 'error');\n  } finally {\n    btn.disabled = false; btn.textContent = 'Guardar reporte';\n  }\n}\n\n// \u2500\u2500 CARTA DE COBRO \u2500\u2500\nvar cartaActual = {};\n\nfunction abrirCartaCobro(deudaId, nombre, doc, valor) {\n  cartaActual = { deudaId: deudaId, nombre: nombre, doc: doc, valor: valor };\n  document.getElementById('carta-info').innerHTML =\n    '<strong>'+nombre+'</strong> \u2014 Doc: '+doc+'<br>'\n    +'<span style=\"color:var(--danger);font-weight:700;\">'+valor+'</span>';\n  document.getElementById('carta-preview').textContent =\n    'CLAVO5: '+nombre+', tienes una obligacion en mora de '+valor+\n    ' reportada en Clavo5. Contacta a la empresa para negociar. Info: contacto@plataformac5.com';\n  document.getElementById('modal-carta').style.display = 'flex';\n}\n\nasync function enviarCartaCobro() {\n  const btn = document.getElementById('btn-carta');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Enviando...';\n\n  try {\n    // Registrar en auditor\u00eda\n    await registrarAuditoria('CARTA_COBRO', 'Fac_deudas', cartaActual.deudaId,\n      null, { nombre: cartaActual.nombre, valor: cartaActual.valor });\n\n    // Aqu\u00ed se integrar\u00e1 Twilio SMS cuando est\u00e9 disponible\n    // Por ahora registramos el intento\n    toast('\ud83d\udce8 Carta de cobro enviada exitosamente', 'success');\n    cerrarModal('modal-carta');\n  } catch(e) {\n    toast('Error: ' + e.message, 'error');\n  } finally {\n    btn.disabled = false; btn.textContent = '\ud83d\udce8 Enviar carta \u2014 $1.900';\n  }\n}\n\n// \u2500\u2500 EXPORTAR EXCEL \u2500\u2500\nfunction exportarExcel() {\n  if (!morososData || morososData.length === 0) {\n    toast('No hay datos para exportar', 'error'); return;\n  }\n\n  var csv = 'Credito,Nombre,Documento,Departamento,Ciudad,Valor Deuda,Vencimiento,Observacion\\n';\n  morososData.forEach(function(d) {\n    csv += '\"Credito #'+d.id+'\",\"'+(d._nombre||'')+'\",'\n      +'\"'+(d._doc||'')+'\",\"'+(d._depto||'')+'\",\"'+(d._mpio||'')+'\",\"'\n      +(d._valor||'')+'\",\"'+(d._fecha||'')+'\",\"'+(d.Observacion||'')+'\"\\n';\n  });\n\n  const blob = new Blob(['\\uFEFF'+csv], { type: 'text/csv;charset=utf-8;' });\n  const url  = URL.createObjectURL(blob);\n  const a    = document.createElement('a');\n  a.href = url;\n  a.download = 'morosos_'+state.empresa.Nombre_Empresa.replace(/\\s/g,'_')+'_'+new Date().toISOString().split('T')[0]+'.csv';\n  a.click();\n  URL.revokeObjectURL(url);\n  toast('\ud83d\udce5 Archivo exportado', 'success');\n}\n\n// \u2500\u2500 VERIFICACI\u00d3N MASIVA \u2500\u2500\nasync function procesarArchivoMasivo(input) {\n  const file = input.files[0];\n  if (!file) return;\n\n  const div = document.getElementById('masiva-resultado');\n  div.style.display = 'block';\n  div.innerHTML = '<div style=\"text-align:center;padding:20px;color:var(--text-muted);\"><span class=\"spinner\"></span> Procesando archivo...</div>';\n\n  try {\n    const text = await file.text();\n    const lineas = text.split('\\n').filter(function(l){ return l.trim(); });\n\n    // Parsear CSV simple (tipo doc, numero doc)\n    var documentos = [];\n    lineas.forEach(function(linea, idx) {\n      if (idx === 0) return; // saltar encabezado\n      var cols = linea.split(',');\n      if (cols.length >= 2) {\n        documentos.push({\n          tipoDoc: cols[0].replace(/\"/g,'').trim(),\n          numDoc:  cols[1].replace(/\"/g,'').trim()\n        });\n      }\n    });\n\n    if (documentos.length === 0) {\n      div.innerHTML = '<div style=\"color:var(--danger);padding:10px;\">No se encontraron datos v\u00e1lidos en el archivo.</div>';\n      return;\n    }\n\n    // Buscar cada documento en la BD\n    var numDocs = documentos.map(function(d){ return d.numDoc; });\n    const { data: personas } = await supa.from('Tbl_Persona')\n      .select('id, Nro_documento')\n      .in('Nro_documento', numDocs);\n\n    const docsConReporte = new Set((personas||[]).map(function(p){ return p.Nro_documento; }));\n\n    var html = '<div style=\"font-size:13px;margin-bottom:10px;color:var(--text);\">'\n      +'<strong>'+documentos.length+'</strong> documentos verificados \u2014 '\n      +'<span style=\"color:var(--danger)\"><strong>'+docsConReporte.size+'</strong> con reportes</span></div>';\n\n    html += '<table style=\"width:100%;border-collapse:collapse;font-size:12px;\">';\n    html += '<thead><tr style=\"background:var(--surface2);\">'\n      +'<th style=\"padding:8px;text-align:left;\">Documento</th>'\n      +'<th style=\"padding:8px;text-align:left;\">Estado</th>'\n      +'</tr></thead><tbody>';\n\n    documentos.forEach(function(d) {\n      const tiene = docsConReporte.has(d.numDoc);\n      html += '<tr style=\"border-top:1px solid var(--border);\">'\n        +'<td style=\"padding:8px;color:var(--text-muted);\">'+d.numDoc+'</td>'\n        +'<td style=\"padding:8px;\">'\n        +(tiene\n          ? '<span style=\"color:var(--danger);font-weight:600;\">\u26a0 Reportado</span>'\n          : '<span style=\"color:var(--accent);\">\u2713 Sin reportes</span>')\n        +'</td></tr>';\n    });\n\n    html += '</tbody></table>';\n    div.innerHTML = html;\n\n    toast('\u2705 Verificaci\u00f3n completada: '+docsConReporte.size+' con reportes de '+documentos.length, 'info');\n\n  } catch(e) {\n    div.innerHTML = '<div style=\"color:var(--danger);padding:10px;\">Error procesando el archivo: '+e.message+'</div>';\n  }\n}\n\nfunction descargarPlantilla() {\n  const csv = 'Tipo Documento,Numero Documento\\nCC,1045109841\\nCC,44444444444\\nNIT,900123456';\n  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });\n  const url  = URL.createObjectURL(blob);\n  const a    = document.createElement('a');\n  a.href = url; a.download = 'plantilla_verificacion_masiva.csv'; a.click();\n  URL.revokeObjectURL(url);\n}\nfunction verPlanes() {\n  document.getElementById('modal-planes').style.display = 'flex';\n}\n\n// \u2500\u2500 CARTA DE COBRO \u2500\u2500\nvar cartaSeleccionados = [];\n\nasync function abrirCartaCobro() {\n  cartaSeleccionados = [];\n  const lista = document.getElementById('carta-lista');\n  lista.innerHTML = '<div style=\"text-align:center;padding:20px;color:var(--text-muted);\"><span class=\"spinner\"></span> Cargando...</div>';\n  document.getElementById('modal-carta-cobro').style.display = 'flex';\n\n  const { data: deudas } = await supa.from('Fac_deudas').select('id, Valor_total_deuda, Id_persona, celular_deudor').eq('Id_empresa', state.empresa.id);\n  if (!deudas || deudas.length === 0) { lista.innerHTML = '<div style=\"text-align:center;padding:20px;color:var(--text-muted);\">No tienes morosos registrados.</div>'; return; }\n\n  const personaIds = deudas.map(function(d){ return d.Id_persona; });\n  const { data: personas } = await supa.from('Tbl_Persona').select('id, Nombre_persona, Nro_documento').in('id', personaIds);\n  var pMap = {};\n  (personas||[]).forEach(function(p){ pMap[p.id] = p; });\n\n  var html = '';\n  deudas.forEach(function(d) {\n    const p = pMap[d.Id_persona] || {};\n    const valor = '$'+parseFloat(d.Valor_total_deuda).toLocaleString('es-CO',{maximumFractionDigits:0});\n    const tieneCelular = d.celular_deudor ? true : false;\n    html += '<div style=\"display:flex;align-items:center;gap:10px;padding:10px;background:var(--surface2);border-radius:8px;margin-bottom:8px;\">';\n    html += '<input type=\"checkbox\" id=\"carta-'+d.id+'\" '+(tieneCelular?'':'disabled title=\"Sin celular registrado\"')+' onchange=\"toggleCarta('+d.id+')\" style=\"width:16px;height:16px;accent-color:var(--accent);cursor:'+(tieneCelular?'pointer':'not-allowed')+';\"/>';\n    html += '<label for=\"carta-'+d.id+'\" style=\"flex:1;cursor:pointer;font-size:13px;\">';\n    html += '<div style=\"font-weight:600;color:var(--text);\">'+(p.Nombre_persona||'-')+'</div>';\n    html += '<div style=\"color:var(--text-muted);font-size:11px;\">Doc: '+(p.Nro_documento||'-')+' \u2014 '+valor;\n    html += tieneCelular ? ' \u2014 \ud83d\udcf1 +57 '+d.celular_deudor : ' \u2014 <span style=\"color:var(--danger);\">Sin celular</span>';\n    html += '</div></label></div>';\n  });\n  lista.innerHTML = html;\n}\n\nfunction toggleCarta(id) {\n  const idx = cartaSeleccionados.indexOf(id);\n  if (idx === -1) cartaSeleccionados.push(id);\n  else cartaSeleccionados.splice(idx, 1);\n  document.getElementById('carta-count').textContent = cartaSeleccionados.length;\n  document.getElementById('carta-total').textContent = '$'+(cartaSeleccionados.length * 1900).toLocaleString('es-CO');\n}\n\nfunction enviarCartasCobro() {\n  if (cartaSeleccionados.length === 0) { toast('Selecciona al menos un deudor', 'error'); return; }\n  pagarConBold('cartas', cartaSeleccionados.length * 1900);\n  cerrarModal('modal-carta-cobro');\n}\n\n\n\nasync function ejecutarVerificacionMasiva() {\n  if (masivaDocumentos.length === 0) { toast('Carga un archivo primero', 'error'); return; }\n  const btn = document.getElementById('btn-masiva');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Verificando...';\n  const preview = document.getElementById('masiva-preview');\n  try {\n    const { data: personas } = await supa.from('Tbl_Persona').select('id, Nro_documento, Nombre_persona').in('Nro_documento', masivaDocumentos);\n    const reportados = new Set((personas||[]).map(function(p){ return p.Nro_documento; }));\n\n    let html = '<div style=\"background:var(--surface2);border-radius:8px;padding:14px;\">';\n    html += '<div style=\"font-family:Syne,sans-serif;font-weight:700;font-size:14px;margin-bottom:12px;\">Resultados</div>';\n    html += '<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px;\">';\n    html += '<div style=\"background:rgba(255,77,109,.08);border-radius:8px;padding:12px;text-align:center;\"><div style=\"font-family:Syne,sans-serif;font-weight:800;font-size:28px;color:var(--danger);\">'+reportados.size+'</div><div style=\"font-size:12px;color:var(--text-muted);\">Reportados</div></div>';\n    html += '<div style=\"background:rgba(0,212,170,.08);border-radius:8px;padding:12px;text-align:center;\"><div style=\"font-family:Syne,sans-serif;font-weight:800;font-size:28px;color:var(--accent);\">'+(masivaDocumentos.length-reportados.size)+'</div><div style=\"font-size:12px;color:var(--text-muted);\">Sin reportes</div></div>';\n    html += '</div>';\n    if (reportados.size > 0) {\n      html += '<div style=\"font-size:12px;font-weight:600;color:var(--danger);margin-bottom:8px;\">Documentos reportados:</div>';\n      (personas||[]).slice(0,20).forEach(function(p){ html += '<div style=\"font-size:12px;color:var(--text-muted);padding:4px 0;border-bottom:1px solid var(--border);\">'+p.Nro_documento+' \u2014 '+p.Nombre_persona+'</div>'; });\n      if (reportados.size > 20) html += '<div style=\"font-size:11px;color:var(--text-dim);margin-top:6px;\">...y '+(reportados.size-20)+' mas</div>';\n    }\n    html += '</div>';\n    preview.innerHTML = html;\n    await registrarAuditoria('VERIFICACION_MASIVA', 'Tbl_Persona', null, null, { total: masivaDocumentos.length, reportados: reportados.size });\n  } catch(e) {\n    preview.innerHTML = '<div style=\"color:var(--danger);font-size:13px;\">Error: '+e.message+'</div>';\n  } finally {\n    btn.disabled = false; btn.textContent = 'Verificar documentos';\n  }\n}\n\nasync function pagarConBold(plan, valor) {\n  toast('Preparando pago...', 'info');\n  try {\n    const res = await fetch('/functions/crear-pago', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        plan: plan,\n        valor: valor,\n        empresa_id: state.empresa.id,\n        empresa_nombre: state.empresa['Nombre del responsable'] || state.empresa.Nombre_Empresa,\n        celular: state.empresa.Celular\n      })\n    });\n\n    const data = await res.json();\n\n    if (!res.ok || !data.url) {\n      toast('Error al crear el pago. Intenta de nuevo.', 'error');\n      return;\n    }\n\n    const planId = plan === 'estandar' ? 2 : plan === 'premium' ? 3 : 4;\n    await supa.from('Tbl_Suscripciones').insert({\n      empresa_id: state.empresa.id,\n      plan_id: planId,\n      fecha_inicio: new Date().toISOString().split('T')[0],\n      fecha_vencimiento: new Date(Date.now() + 30*24*60*60*1000).toISOString().split('T')[0],\n      estado: 'pendiente',\n      forma_pago: 'bold',\n      observacion: data.referencia\n    });\n\n    window.open(data.url, '_blank');\n    toast('Redirigiendo a Bold para pago seguro...', 'info');\n\n  } catch(e) {\n    toast('Error: ' + e.message, 'error');\n  }\n}\n\n// \u2500\u2500 SELECTOR DE FECHA MEJORADO \u2500\u2500\nfunction inicializarSelectoresFecha() {\n  var hoy = new Date();\n  var anioActual = hoy.getFullYear();\n\n  // Fecha m\u00e1xima = hoy - 60 d\u00edas\n  var maxFecha = new Date();\n  maxFecha.setDate(maxFecha.getDate() - 60);\n  var maxAnio = maxFecha.getFullYear();\n\n  ['m','e'].forEach(function(p) {\n    var selAnio = document.getElementById(p+'-fecha-anio');\n    if (!selAnio) return;\n    selAnio.innerHTML = '<option value=\"\">A\u00f1o</option>';\n    // Mostrar \u00faltimos 5 a\u00f1os hasta el a\u00f1o de la fecha m\u00e1xima\n    for (var a = maxAnio - 4; a <= maxAnio; a++) {\n      selAnio.innerHTML += '<option value=\"'+a+'\">'+a+'</option>';\n    }\n    selAnio.onchange = function() { actualizarMesesFecha(p); };\n\n    var selMes = document.getElementById(p+'-fecha-mes');\n    if (selMes) selMes.onchange = function() { actualizarDiasFecha(p); };\n  });\n}\n\nfunction actualizarMesesFecha(prefix) {\n  var anio = parseInt(document.getElementById(prefix+'-fecha-anio').value);\n  var selMes = document.getElementById(prefix+'-fecha-mes');\n  if (!selMes || !anio) return;\n\n  var maxFecha = new Date();\n  maxFecha.setDate(maxFecha.getDate() - 60);\n  var maxAnio = maxFecha.getFullYear();\n  var maxMes  = maxFecha.getMonth() + 1;\n\n  var meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];\n  var mesFin = (anio === maxAnio) ? maxMes : 12;\n\n  selMes.innerHTML = '<option value=\"\">Mes</option>';\n  for (var m = 1; m <= mesFin; m++) {\n    selMes.innerHTML += '<option value=\"'+m+'\">'+meses[m-1]+'</option>';\n  }\n  document.getElementById(prefix+'-fecha-dia').innerHTML = '<option value=\"\">D\u00eda</option>';\n}\n\nfunction actualizarDiasFecha(prefix) {\n  var mes  = parseInt(document.getElementById(prefix+'-fecha-mes').value) || 1;\n  var anio = parseInt(document.getElementById(prefix+'-fecha-anio').value) || new Date().getFullYear();\n  var selDia = document.getElementById(prefix+'-fecha-dia');\n  if (!selDia) return;\n\n  var maxFecha = new Date();\n  maxFecha.setDate(maxFecha.getDate() - 60);\n  var maxAnio = maxFecha.getFullYear();\n  var maxMes  = maxFecha.getMonth() + 1;\n  var maxDia  = maxFecha.getDate();\n\n  var diasEnMes = new Date(anio, mes, 0).getDate();\n  var diaFin = (anio === maxAnio && mes === maxMes) ? maxDia : diasEnMes;\n  var diaActual = parseInt(selDia.value) || 0;\n\n  selDia.innerHTML = '<option value=\"\">D\u00eda</option>';\n  for (var d = 1; d <= diaFin; d++) {\n    selDia.innerHTML += '<option value=\"'+d+'\"'+(d===diaActual?' selected':'')+'>'+d+'</option>';\n  }\n}\n\nfunction getFechaFromSelectors(prefix) {\n  var dia  = document.getElementById(prefix+'-fecha-dia').value;\n  var mes  = document.getElementById(prefix+'-fecha-mes').value;\n  var anio = document.getElementById(prefix+'-fecha-anio').value;\n  if (!dia || !mes || !anio) return null;\n  return anio + '-' + mes.padStart(2,'0') + '-' + dia.padStart(2,'0');\n}\n\nfunction setFechaToSelectors(prefix, fechaStr) {\n  if (!fechaStr) return;\n  var parts = fechaStr.split('-');\n  if (parts.length !== 3) return;\n  document.getElementById(prefix+'-fecha-anio').value = parts[0];\n  document.getElementById(prefix+'-fecha-mes').value  = parseInt(parts[1]).toString();\n  actualizarDiasFecha(prefix);\n  document.getElementById(prefix+'-fecha-dia').value  = parseInt(parts[2]).toString();\n}\n\nfunction validarFecha60Dias(fechaStr) {\n  if (!fechaStr) return false;\n  var fecha = new Date(fechaStr + 'T00:00:00');\n  var maxFecha = new Date();\n  maxFecha.setDate(maxFecha.getDate() - 60);\n  maxFecha.setHours(0,0,0,0);\n  return fecha <= maxFecha;\n}\n\n// \u2500\u2500 RECUPERAR CONTRASE\u00d1A POR OTP \u2500\u2500\nvar forgotOTP = null;\nvar forgotCelular = null;\n\nasync function enviarOTPRecuperacion() {\n  const celular = document.getElementById('forgot-celular').value.trim().replace(/\\s/g,'');\n  if (!celular || celular.length < 10) { toast('Ingresa un celular v\u00e1lido', 'error'); return; }\n\n  const { data: emp } = await supa.from('Tbl_Empresa').select('id').eq('Celular', celular).maybeSingle();\n  if (!emp) { toast('Este celular no est\u00e1 registrado', 'error'); return; }\n\n  const btn = document.getElementById('btn-forgot');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Enviando...';\n\n  forgotOTP     = Math.floor(100000 + Math.random() * 900000).toString();\n  forgotCelular = celular;\n\n  try {\n    const res = await fetch('/functions/enviar-sms', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ celular: celular, mensaje: 'Plataforma C5 \u2014 Tu c\u00f3digo para restablecer contrase\u00f1a es: ' + forgotOTP + '. V\u00e1lido por 10 minutos.' })\n    });\n    const data = await res.json();\n    if (!data.ok) throw new Error('SMS fallido');\n    document.getElementById('forgot-demo-box').style.display = 'none';\n  } catch(e) {\n    document.getElementById('forgot-demo-code').textContent = forgotOTP;\n    document.getElementById('forgot-demo-box').style.display = 'block';\n  }\n\n  [0,1,2,3,4,5].forEach(function(i){ var el = document.getElementById('fo'+i); if(el) el.value=''; });\n  document.getElementById('forgot-otp-desc').textContent = 'Ingresa el c\u00f3digo enviado al +57 ' + celular.slice(0,3) + '***' + celular.slice(-2);\n  btn.disabled = false; btn.textContent = 'Enviar c\u00f3digo SMS';\n  showScreen('forgot-otp');\n}\n\nasync function verificarOTPRecuperacion() {\n  const codigo = getOTP('fo');\n  if (codigo.length < 6) { toast('Ingresa los 6 d\u00edgitos', 'error'); return; }\n  if (codigo !== forgotOTP) { toast('C\u00f3digo incorrecto', 'error'); return; }\n  showScreen('forgot-newpass');\n  document.getElementById('new-pass').value = '';\n  document.getElementById('new-pass2').value = '';\n}\n\nasync function guardarNuevaContrasena() {\n  const pass  = document.getElementById('new-pass').value;\n  const pass2 = document.getElementById('new-pass2').value;\n  if (!pass || pass.length < 8) { toast('M\u00ednimo 8 caracteres', 'error'); return; }\n  if (pass !== pass2) { toast('Las contrase\u00f1as no coinciden', 'error'); return; }\n\n  const btn = document.getElementById('btn-newpass');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Guardando...';\n\n  try {\n    const res = await fetch('/functions/cambiar-contrasena', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ celular: forgotCelular, password: pass })\n    });\n    const data = await res.json();\n    if (!res.ok) throw new Error(data.error || 'Error al cambiar contrase\u00f1a');\n    toast('\u2705 Contrase\u00f1a actualizada. Inicia sesi\u00f3n.', 'success');\n    document.getElementById('login-celular').value = forgotCelular;\n    setTimeout(function(){ showScreen('login'); }, 1500);\n  } catch(e) {\n    toast('Error: ' + e.message, 'error');\n  } finally {\n    btn.disabled = false; btn.textContent = 'Guardar contrase\u00f1a';\n  }\n}\n\n// \u2500\u2500 FILTRO M\u00d3DULO SOLICITUDES \u2500\u2500\nasync function verSolicitudes() {\n  document.getElementById('solicitudes-lista').innerHTML =\n    '<div style=\"text-align:center;padding:30px;color:var(--text-muted);\"><span class=\"spinner\"></span> Cargando...</div>';\n  document.getElementById('modal-solicitudes').style.display = 'flex';\n  await cargarSolicitudes('todas', '');\n}\n\nasync function cargarSolicitudes(filtroEstado, busqueda) {\n  let query = supa.from('Tbl_Solicitudes_Correccion').select('*').eq('empresa_id', state.empresa.id).order('created_at', { ascending: false });\n  if (filtroEstado && filtroEstado !== 'todas') query = query.eq('estado', filtroEstado);\n  const { data: sols } = await query;\n\n  const tiposLabel = { 'error_datos':'Error en datos','deuda_pagada':'Deuda pagada','deuda_inexistente':'Deuda inexistente','otro':'Otro motivo' };\n  let lista = sols || [];\n  if (busqueda) {\n    const b = busqueda.toLowerCase();\n    lista = lista.filter(function(s){ return s.nombre_solicitante.toLowerCase().includes(b) || (s.deuda_id+'').includes(b) || s.celular_solicitante.includes(b); });\n  }\n\n  const pendientes = (sols||[]).filter(function(s){ return s.estado==='pendiente'; }).length;\n  document.getElementById('btn-solicitudes').textContent = '\ud83d\udccb Solicitudes' + (pendientes > 0 ? ' ('+pendientes+')' : '');\n\n  var html = '<div style=\"padding:0 0 14px 0;display:flex;gap:8px;flex-wrap:wrap;\">';\n  html += '<select onchange=\"cargarSolicitudes(this.value,document.getElementById(\\'sol-busqueda\\').value||\\'\\')\" style=\"background:var(--surface2);border:1px solid var(--border);border-radius:8px;padding:8px 12px;color:var(--text);font-size:12px;font-family:DM Sans,sans-serif;outline:none;\">';\n  html += '<option value=\"todas\">Todas</option><option value=\"pendiente\">Pendientes</option><option value=\"resuelta\">Resueltas</option><option value=\"rechazada\">Rechazadas</option>';\n  html += '</select>';\n  html += '<input id=\"sol-busqueda\" type=\"text\" placeholder=\"Buscar por nombre o cr\u00e9dito...\" oninput=\"cargarSolicitudes(\\'todas\\',this.value)\" style=\"flex:1;min-width:150px;background:var(--surface2);border:1px solid var(--border);border-radius:8px;padding:8px 12px;color:var(--text);font-size:12px;font-family:DM Sans,sans-serif;outline:none;\"/>';\n  html += '</div>';\n\n  if (lista.length === 0) { html += '<div style=\"text-align:center;padding:40px;color:var(--text-muted);\">No hay solicitudes.</div>'; document.getElementById('solicitudes-lista').innerHTML = html; return; }\n\n  lista.forEach(function(s) {\n    const fecha = new Date(s.created_at).toLocaleDateString('es-CO',{day:'2-digit',month:'short',year:'numeric'});\n    const estadoColor = s.estado==='pendiente'?'#ffb347':s.estado==='resuelta'?'var(--accent)':'var(--danger)';\n    html += '<div style=\"background:var(--surface2);border-radius:10px;padding:14px;margin-bottom:10px;font-size:13px;\">';\n    html += '<div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;\"><span style=\"font-weight:600;color:var(--text);\">Cr\u00e9dito #'+s.deuda_id+' \u2014 '+s.nombre_solicitante+'</span><span style=\"color:'+estadoColor+';font-size:11px;font-weight:600;\">'+s.estado.toUpperCase()+'</span></div>';\n    html += '<div style=\"color:var(--accent2);font-size:11px;margin-bottom:4px;\">'+(tiposLabel[s.tipo_solicitud]||s.tipo_solicitud)+'</div>';\n    html += '<div style=\"color:var(--text-muted);\">'+s.descripcion+'</div>';\n    html += '<div style=\"color:var(--text-muted);font-size:11px;margin-top:6px;\">\ud83d\udcf1 +57 '+s.celular_solicitante+' \u2014 '+fecha+'</div>';\n    if (s.respuesta) html += '<div style=\"color:var(--text-muted);font-size:11px;margin-top:4px;font-style:italic;\">Respuesta: '+s.respuesta+'</div>';\n    if (s.estado === 'pendiente') {\n      html += '<div style=\"display:flex;gap:8px;margin-top:10px;\">';\n      html += '<button onclick=\"resolverSolicitud('+s.id+',\\'resuelta\\',\\'\\',\\''+s.celular_solicitante+'\\','+s.deuda_id+')\" style=\"background:rgba(0,212,170,.12);border:1px solid rgba(0,212,170,.3);color:var(--accent);border-radius:6px;padding:6px 12px;font-size:12px;cursor:pointer;\">\u2713 Resolver</button>';\n      html += '<button onclick=\"pedirMotivoRechazo('+s.id+',\\''+s.celular_solicitante+'\\','+s.deuda_id+')\" style=\"background:rgba(255,77,109,.12);border:1px solid rgba(255,77,109,.3);color:var(--danger);border-radius:6px;padding:6px 12px;font-size:12px;cursor:pointer;\">\u2717 Rechazar</button>';\n      html += '</div>';\n    }\n    html += '</div>';\n  });\n  document.getElementById('solicitudes-lista').innerHTML = html;\n}\n\nfunction pedirMotivoRechazo(solId, celularSolicitante, deudaId) {\n  var motivo = prompt('\u00bfPor qu\u00e9 rechazas esta solicitud? (obligatorio)');\n  if (!motivo || motivo.trim() === '') { toast('Debes ingresar el motivo del rechazo', 'error'); return; }\n  resolverSolicitud(solId, 'rechazada', motivo.trim(), celularSolicitante, deudaId);\n}\n\nasync function resolverSolicitud(id, estado, respuesta, celularSolicitante, deudaId) {\n  await supa.from('Tbl_Solicitudes_Correccion').update({ estado: estado, respuesta: respuesta || null }).eq('id', id);\n  if (celularSolicitante) {\n    var msgSMS = estado === 'resuelta'\n      ? 'Tu solicitud de correcci\u00f3n del Cr\u00e9dito #'+deudaId+' fue ACEPTADA. \u2014 Plataforma C5'\n      : 'Tu solicitud de correcci\u00f3n del Cr\u00e9dito #'+deudaId+' fue RECHAZADA. Motivo: '+respuesta+' \u2014 Plataforma C5';\n    fetch('/functions/enviar-sms', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ celular: celularSolicitante, mensaje: msgSMS }) });\n  }\n  toast('Solicitud ' + estado, 'info');\n  cargarSolicitudes('todas', '');\n}\n\nfunction abrirTerminos() {\n  document.getElementById('modal-terminos').style.display = 'flex';\n}\n\nfunction aceptarTerminos() {\n  document.getElementById('reg-terminos').checked = true;\n  cerrarModal('modal-terminos');\n  toast('T\u00e9rminos aceptados', 'success');\n}\n\n// \u2500\u2500 SOLICITUD DE CORRECCI\u00d3N \u2500\u2500\nfunction abrirCorreccion(deudaId, empresaId, empresaNombre, valor) {\n  document.getElementById('cor-deuda-id').value  = deudaId;\n  document.getElementById('cor-empresa-id').value = empresaId;\n  document.getElementById('cor-info').innerHTML =\n    '<strong style=\"color:var(--text);\">'+empresaNombre+'</strong><br>'\n    +'Cr\u00e9dito #'+deudaId+' \u2014 <span style=\"color:var(--danger);font-weight:700;\">'+valor+'</span>';\n  document.getElementById('cor-nombre').value      = '';\n  document.getElementById('cor-celular').value     = '';\n  document.getElementById('cor-tipo').value        = '';\n  document.getElementById('cor-descripcion').value = '';\n  document.getElementById('modal-correccion').style.display = 'flex';\n}\n\nasync function enviarCorreccion() {\n  const nombre      = document.getElementById('cor-nombre').value.trim();\n  const celular     = document.getElementById('cor-celular').value.trim().replace(/\\s/g,'');\n  const tipo        = document.getElementById('cor-tipo').value;\n  const descripcion = document.getElementById('cor-descripcion').value.trim();\n  const deudaId     = document.getElementById('cor-deuda-id').value;\n  const empresaId   = document.getElementById('cor-empresa-id').value;\n\n  if (!nombre)      { toast('Tu nombre es obligatorio', 'error'); return; }\n  if (!celular || celular.length < 10) { toast('Ingresa un celular valido', 'error'); return; }\n  if (!tipo)        { toast('Selecciona el tipo de solicitud', 'error'); return; }\n  if (!descripcion) { toast('Describe tu solicitud', 'error'); return; }\n\n  const btn = document.getElementById('btn-correccion');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Enviando...';\n\n  try {\n    const { error } = await supa.from('Tbl_Solicitudes_Correccion').insert({\n      deuda_id: parseInt(deudaId),\n      empresa_id: parseInt(empresaId),\n      nombre_solicitante: nombre,\n      celular_solicitante: celular,\n      tipo_solicitud: tipo,\n      descripcion: descripcion,\n      estado: 'pendiente'\n    });\n    if (error) throw new Error(error.message);\n    cerrarModal('modal-correccion');\n    toast('\u2705 Solicitud enviada. La empresa la revisar\u00e1 en 5 d\u00edas h\u00e1biles.', 'success');\n  } catch(e) {\n    toast('Error: ' + e.message, 'error');\n  } finally {\n    btn.disabled = false; btn.textContent = 'Enviar solicitud';\n  }\n}\n\n// \u2500\u2500 B\u00daSQUEDA MOROSOS \u2500\u2500\nvar morososData = [];\n\nfunction filtrarMorosos() {\n  const termino = document.getElementById('search-input').value.toLowerCase().trim();\n  if (!termino) { renderMorosos(morososData); return; }\n  const filtrados = morososData.filter(function(d) {\n    return (d._nombre||'').toLowerCase().includes(termino) || (d._doc||'').toLowerCase().includes(termino);\n  });\n  renderMorosos(filtrados);\n}\n\nfunction limpiarBusqueda() {\n  document.getElementById('search-input').value = '';\n  renderMorosos(morososData);\n}\n\nfunction renderMorosos(lista) {\n  const tbody = document.getElementById('morosos-tbody');\n  if (!lista || lista.length === 0) {\n    tbody.innerHTML = '<tr><td colspan=\"9\"><div class=\"empty-state\"><div class=\"empty-icon\">\ud83d\udccb</div><div class=\"empty-text\">No se encontraron resultados.</div></div></td></tr>';\n    return;\n  }\n  tbody.innerHTML = '';\n  lista.forEach(function(d) {\n    const tr = document.createElement('tr');\n    tr.innerHTML =\n      '<td style=\"color:var(--accent);font-weight:600;font-size:12px\">Cr\u00e9dito #'+d.id+'</td>'\n      +'<td style=\"font-weight:500\">'+(d._nombre||'-')+'</td>'\n      +'<td style=\"color:var(--text-muted);font-size:12px\">'+(d._doc||'-')+'</td>'\n      +'<td style=\"color:var(--text-muted);font-size:12px\">'+(d._depto||'-')+'</td>'\n      +'<td style=\"color:var(--text-muted);font-size:12px\">'+(d._mpio||'-')+'</td>'\n      +'<td><span class=\"amount\" style=\"color:var(--danger)\">'+(d._valor||'-')+'</span></td>'\n      +'<td style=\"color:var(--text-muted);font-size:12px\">'+(d._fecha||'-')+'</td>'\n      +'<td style=\"color:var(--text-muted);font-size:12px\">'+(d.Observacion||'-')+'</td>'\n      +'<td class=\"td-acciones\">'\n        +'<button class=\"btn-editar\" onclick=\"abrirEditar('+d.id+','+d.Id_persona+')\">\u270f Editar</button>'\n        +'<button class=\"btn-eliminar\" onclick=\"pedirEliminar('+d.id+',\\''+(d._nombre||'').replace(/\\'/g,'')+'\\','+d.Id_persona+')\">\ud83d\uddd1 Eliminar</button>'\n        +'<button onclick=\"abrirCartaCobro('+d.id+',\\''+(d._nombre||'').replace(/\\'/g,'')+'\\',\\''+(d._doc||'')+'\\',\\''+d._valor+'\\')\" style=\"background:rgba(255,179,71,.1);border:1px solid rgba(255,179,71,.3);color:#ffb347;border-radius:6px;padding:6px 10px;font-size:11px;cursor:pointer;white-space:nowrap;font-family:DM Sans,sans-serif;\">\ud83d\udce8 Cobro</button>'\n      +'</td>';\n    tbody.appendChild(tr);\n  });\n}\n\n// \u2500\u2500 B\u00daSQUEDA PERSONA EXISTENTE \u2500\u2500\nvar personaEncontrada = null;\n\nasync function buscarPersonaExistente() {\n  const doc    = document.getElementById('m-documento').value.trim();\n  const tipoId = document.getElementById('m-tipo-doc').value;\n  const alerta = document.getElementById('alerta-persona');\n\n  alerta.style.display = 'none';\n  personaEncontrada = null;\n\n  if (!doc || !tipoId) return;\n\n  // Buscar en el maestro\n  const { data: maestro } = await supa.from('Tbl_Persona')\n    .select('id, Nro_documento')\n    .eq('Nro_documento', doc)\n    .eq('Id_tp_documento', parseInt(tipoId))\n    .maybeSingle();\n\n  if (!maestro) return;\n\n  // Guardar referencia del maestro\n  personaEncontrada = maestro;\n\n  // Buscar todos los nombres registrados por empresas con nombre de la empresa\n  const { data: registros } = await supa.from('Tbl_Persona_Empresa')\n    .select('nombre_empresa, empresa_id, empresa:empresa_id(Nombre_Empresa)')\n    .eq('persona_id', maestro.id);\n\n  if (!registros || registros.length === 0) return;\n\n  // Agrupar por nombre \u00fanico mostrando qu\u00e9 empresas lo usan\n  const nombresMap = {};\n  registros.forEach(function(r) {\n    const nom = r.nombre_empresa;\n    if (!nombresMap[nom]) nombresMap[nom] = [];\n    if (r.empresa && r.empresa.Nombre_Empresa) {\n      nombresMap[nom].push(r.empresa.Nombre_Empresa);\n    }\n  });\n\n  var html = 'Este documento ya est\u00e1 registrado. Selecciona el nombre a usar:<br/>'\n    + '<div style=\"margin-top:10px;display:flex;flex-direction:column;gap:6px;\">';\n\n  Object.keys(nombresMap).forEach(function(nombre) {\n    var nomEsc   = nombre.replace(/'/g, '');\n    var empresas = nombresMap[nombre].join(', ');\n    html += '<button onclick=\"seleccionarNombre(\\'' + nomEsc + '\\')\" '\n      + 'style=\"background:var(--surface2);border:1px solid var(--border);border-radius:8px;'\n      + 'padding:10px 14px;color:var(--text);text-align:left;cursor:pointer;font-family:DM Sans,sans-serif;font-size:13px;\">'\n      + '<span style=\"font-weight:600;display:block;\">' + nombre + '</span>'\n      + '<span style=\"font-size:11px;color:var(--text-muted);\">Registrado por: ' + empresas + '</span>'\n      + '</button>';\n  });\n\n  html += '</div>';\n  document.getElementById('alerta-persona-data').innerHTML = html;\n  alerta.style.display = 'block';\n}\n\nfunction seleccionarNombre(nombre) {\n  document.getElementById('m-nombre').value = nombre;\n  document.getElementById('alerta-persona').style.display = 'none';\n  toast('Nombre seleccionado: ' + nombre, 'info');\n}\n\nfunction seleccionarPersona(idx) {\n  var lista = window._personasEncontradas;\n  if (!lista || !lista[idx]) return;\n  var item = lista[idx];\n  document.getElementById('m-nombre').value = item.nombre || item.Nombre_persona || '';\n  document.getElementById('alerta-persona').style.display = 'none';\n  toast('Nombre seleccionado: ' + (item.nombre || item.Nombre_persona), 'info');\n}\n\nfunction ocultarAlertaPersona() {\n  document.getElementById('alerta-persona').style.display = 'none';\n  document.getElementById('m-nombre').value = '';\n  document.getElementById('m-nombre').focus();\n}\n\n// \u2500\u2500 NEGOCIACI\u00d3N DE DEUDA \u2500\u2500\nvar negociacionActual = {};\n\nfunction abrirNegociacion(deudaId, empresaId, empresaNombre, valor) {\n  negociacionActual = { deudaId: deudaId, empresaId: empresaId, empresaNombre: empresaNombre, valor: valor };\n  document.getElementById('neg-info').innerHTML =\n    '<strong style=\"color:var(--text);\">'+empresaNombre+'</strong><br>'\n    +'Cr\u00e9dito #'+deudaId+' \u2014 <span style=\"color:var(--danger);font-weight:700;\">'+valor+'</span>';\n  document.getElementById('neg-nombre').value  = '';\n  document.getElementById('neg-celular').value = '';\n  document.getElementById('neg-mensaje').value = '';\n  document.getElementById('modal-negociar').style.display = 'flex';\n}\n\nasync function enviarNegociacion() {\n  const nombre  = document.getElementById('neg-nombre').value.trim();\n  const celular = document.getElementById('neg-celular').value.trim().replace(/\\s/g,'');\n  const mensaje = document.getElementById('neg-mensaje').value.trim();\n\n  if (!nombre)  { toast('Tu nombre es obligatorio', 'error'); return; }\n  if (!celular || celular.length < 10) { toast('Ingresa un celular valido de 10 digitos', 'error'); return; }\n\n  const btn = document.getElementById('btn-neg');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Enviando...';\n\n  try {\n    const { error: negErr } = await supa.from('Tbl_Negociaciones').insert({\n      deuda_id: negociacionActual.deudaId,\n      empresa_id: negociacionActual.empresaId,\n      nombre_solicitante: nombre,\n      celular_solicitante: celular,\n      mensaje: mensaje || null,\n      estado: 'pendiente'\n    });\n    if (negErr) throw new Error(negErr.message);\n\n    cerrarModal('modal-negociar');\n    toast('\u2705 Solicitud enviada. La empresa te contactara pronto.', 'success');\n\n  } catch(e) {\n    toast('Error: ' + e.message, 'error');\n  } finally {\n    btn.disabled = false; btn.textContent = 'Enviar solicitud';\n  }\n}\n\nasync function enviarWhatsAppTwilio(destinatario, mensaje) {\n  const accountSid = 'AC1559dc9efe3a9210ab4ee4cb9274b512';\n  const authToken  = '795a33a97e7ac446866050c6a28ca20d';\n  const from       = '+19202557188'; // Numero SMS Twilio trial\n  const to         = destinatario;   // +573001234567\n\n  const body = new URLSearchParams({ From: from, To: to, Body: mensaje });\n\n  const response = await fetch(\n    'https://api.twilio.com/2010-04-01/Accounts/'+accountSid+'/Messages.json',\n    {\n      method: 'POST',\n      headers: {\n        'Authorization': 'Basic ' + btoa(accountSid + ':' + authToken),\n        'Content-Type': 'application/x-www-form-urlencoded'\n      },\n      body: body.toString()\n    }\n  );\n\n  if (!response.ok) {\n    const err = await response.json().catch(function(){ return {}; });\n    console.error('Twilio SMS error:', err.message || err);\n  }\n}\n\nasync function registrarAuditoria(accion, tabla, registroId, datosAnt, datosNuevos) {\n  await supa.from('Tbl_Auditoria').insert({\n    accion: accion,\n    tabla: tabla,\n    registro_id: registroId,\n    datos_anteriores: datosAnt || null,\n    datos_nuevos: datosNuevos || null,\n    empresa_id: state.empresa ? state.empresa.id : null,\n    empresa_nombre: state.empresa ? state.empresa.Nombre_Empresa : null\n  });\n}\n\n// \u2500\u2500 EDITAR MOROSO \u2500\u2500\nasync function abrirEditar(deudaId, personaId) {\n  document.getElementById('e-deuda-id').value  = deudaId;\n  document.getElementById('e-persona-id').value = personaId;\n\n  // Cargar datos\n  const { data: deuda   } = await supa.from('Fac_deudas').select('*').eq('id', deudaId).single();\n  const { data: persona } = await supa.from('Tbl_Persona').select('*').eq('id', personaId).single();\n\n  // Cargar datos espec\u00edficos de la empresa para esta persona\n  const { data: persona_empresa } = await supa.from('Tbl_Persona_Empresa')\n    .select('*')\n    .eq('persona_id', personaId)\n    .eq('empresa_id', state.empresa.id)\n    .maybeSingle();\n\n  // Cargar tipos de documento\n  const { data: tipos } = await supa.from('Tbl_tipo_documento').select('id, Tipo_documento, Descr_tipo_documento').order('Tipo_documento');\n  const selTipo = document.getElementById('e-tipo-doc');\n  selTipo.innerHTML = '<option value=\"\">Selecciona...</option>';\n  if (tipos) tipos.forEach(function(t){\n    selTipo.innerHTML += '<option value=\"'+t.id+'\"'+(persona.Id_tp_documento==t.id?' selected':'')+'>'+t.Tipo_documento+' - '+t.Descr_tipo_documento+'</option>';\n  });\n\n  // Cargar departamentos usando datos de Tbl_Persona_Empresa\n  const deptoActual = persona_empresa ? persona_empresa.id_departamento : null;\n  const { data: deptos } = await supa.from('Tbl_Departamento').select('id, Nombre_Departamento, cod_Departamento').order('Nombre_Departamento');\n  const selDepto = document.getElementById('e-depto');\n  selDepto.innerHTML = '<option value=\"\">Selecciona...</option>';\n  if (deptos) deptos.forEach(function(d){\n    const opt = document.createElement('option');\n    opt.value = d.id; opt.textContent = d.Nombre_Departamento; opt.dataset.cod = d.cod_Departamento;\n    if (deptoActual == d.id) opt.selected = true;\n    selDepto.appendChild(opt);\n  });\n\n  // Cargar municipios\n  const mpioActual = persona_empresa ? persona_empresa.id_municipio : null;\n  await cargarMunicipiosEditar(mpioActual);\n\n  document.getElementById('e-documento').value = persona.Nro_documento || '';\n  document.getElementById('e-nombre').value    = (persona_empresa ? persona_empresa.nombre_empresa : persona.Nombre_persona) || '';\n  document.getElementById('e-valor').value     = parseFloat(deuda.Valor_total_deuda).toLocaleString('es-CO');\n  document.getElementById('e-obs').value       = deuda.Observacion || '';\n  document.getElementById('e-celular-deudor').value = deuda.celular_deudor || '';\n  inicializarSelectoresFecha();\n  setFechaToSelectors('e', deuda.Fecha_Vencimiento_deuda || '');\n\n  state.editDatosAnt = { deuda: deuda, persona: persona, persona_empresa: persona_empresa };\n  document.getElementById('modal-editar').style.display = 'flex';\n}\n\nasync function cargarMunicipiosEditar(mpioSeleccionado) {\n  const selDepto = document.getElementById('e-depto');\n  const selMpio  = document.getElementById('e-mpio');\n  const opt = selDepto.options[selDepto.selectedIndex];\n  const codDepto = opt ? opt.dataset.cod : null;\n  selMpio.innerHTML = '<option value=\"\">Selecciona municipio...</option>';\n  if (!codDepto) return;\n  const { data: mpios } = await supa.from('Tbl_municipios').select('id, Nombre_mpio').eq('Cod_departamento', codDepto).order('Nombre_mpio');\n  if (mpios) mpios.forEach(function(m){\n    selMpio.innerHTML += '<option value=\"'+m.id+'\"'+(mpioSeleccionado==m.id?' selected':'')+'>'+m.Nombre_mpio+'</option>';\n  });\n}\n\nasync function actualizarMoroso() {\n  const deudaId   = document.getElementById('e-deuda-id').value;\n  const personaId = document.getElementById('e-persona-id').value;\n  const tipoDoc   = document.getElementById('e-tipo-doc').value;\n  const documento = document.getElementById('e-documento').value.trim();\n  const nombre    = document.getElementById('e-nombre').value.trim();\n  const deptoId   = document.getElementById('e-depto').value;\n  const mpioId    = document.getElementById('e-mpio').value;\n  const valorRaw  = document.getElementById('e-valor').value.replace(/\\./g,'').replace(/,/g,'').trim();\n  const fecha     = getFechaFromSelectors('e');\n  const obs       = document.getElementById('e-obs').value.trim();\n\n  if (!tipoDoc||!documento||!nombre||!deptoId||!mpioId||!valorRaw||!fecha) { toast('Completa todos los campos obligatorios', 'error'); return; }\n  if (!validarFecha60Dias(fecha)) { toast('La deuda debe tener m\u00ednimo 2 meses de antig\u00fcedad', 'error'); return; }\n\n  const btn = document.getElementById('btn-actualizar');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Guardando...';\n\n  try {\n    // Actualizar datos espec\u00edficos de la empresa en Tbl_Persona_Empresa\n    await supa.from('Tbl_Persona_Empresa').upsert({\n      persona_id: parseInt(personaId),\n      empresa_id: state.empresa.id,\n      nombre_empresa: nombre,\n      id_departamento: parseInt(deptoId),\n      id_municipio: parseInt(mpioId)\n    }, { onConflict: 'persona_id,empresa_id' });\n\n    // Actualizar deuda\n    const datosNuevosDeuda = { Valor_total_deuda: parseFloat(valorRaw), Fecha_Vencimiento_deuda: fecha, Observacion: obs||null, celular_deudor: document.getElementById('e-celular-deudor').value.trim()||null };\n    await supa.from('Fac_deudas').update(datosNuevosDeuda).eq('id', deudaId);\n\n    await registrarAuditoria('MODIFICACION', 'Fac_deudas+Tbl_Persona_Empresa', deudaId,\n      state.editDatosAnt, { nombre, deptoId, mpioId, ...datosNuevosDeuda });\n\n    toast('Reporte actualizado', 'success');\n    cerrarModal('modal-editar');\n    cargarMorosos();\n  } catch(e) {\n    toast('Error: ' + e.message, 'error');\n  } finally {\n    btn.disabled = false; btn.textContent = 'Guardar cambios';\n  }\n}\n\n// \u2500\u2500 VERIFICAR PERSONA (pantalla bienvenida) \u2500\u2500\nasync function cargarTiposDocVerificacion() {\n  const { data: tipos } = await supa.from('Tbl_tipo_documento').select('id, Tipo_documento').order('Tipo_documento');\n  const sel = document.getElementById('v-tipo-doc');\n  if (!sel) return;\n  sel.innerHTML = '<option value=\"\">Selecciona...</option>';\n  if (tipos) tipos.forEach(function(t){\n    sel.innerHTML += '<option value=\"'+t.id+'\">'+t.Tipo_documento+'</option>';\n  });\n}\n\n// \u2500\u2500 CONTROL DE CONSULTAS POR IP \u2500\u2500\nvar ipActual = null;\n\nasync function obtenerIP() {\n  if (ipActual) return ipActual;\n  try {\n    const res = await fetch('https://api.ipify.org?format=json');\n    const data = await res.json();\n    ipActual = data.ip;\n  } catch(e) {\n    ipActual = 'unknown';\n  }\n  return ipActual;\n}\n\nasync function verificarLimiteConsultas() {\n  const ip = await obtenerIP();\n  const inicioMes = new Date();\n  inicioMes.setDate(1); inicioMes.setHours(0,0,0,0);\n\n  const { data: consultas } = await supa.from('Tbl_Consultas')\n    .select('id')\n    .eq('ip_address', ip)\n    .gte('created_at', inicioMes.toISOString());\n\n  const total = consultas ? consultas.length : 0;\n  return { total: total, ip: ip, limite: 3, restantes: Math.max(0, 3 - total) };\n}\n\nasync function registrarConsulta(doc, tipoId, encontrado) {\n  const ip = await obtenerIP();\n  await supa.from('Tbl_Consultas').insert({\n    ip_address: ip,\n    documento_consultado: doc,\n    tipo_documento_id: tipoId,\n    encontrado: encontrado\n  });\n}\n\nasync function verificarPersona() {\n  const tipoId = document.getElementById('v-tipo-doc').value;\n  const doc    = document.getElementById('v-documento').value.trim();\n  if (!tipoId) { toast('Selecciona el tipo de documento', 'error'); return; }\n  if (!doc)    { toast('Ingresa el numero de documento', 'error'); return; }\n\n  const btn = document.getElementById('btn-verificar');\n  btn.disabled = true; btn.innerHTML = '<span class=\"spinner\"></span> Consultando...';\n\n  const div = document.getElementById('v-resultado');\n  div.style.display = 'none'; div.innerHTML = '';\n\n  try {\n    // Verificar l\u00edmite de consultas por IP\n    const limite = await verificarLimiteConsultas();\n    if (limite.restantes === 0) {\n      div.style.display = 'block';\n      div.innerHTML = '<div style=\"background:rgba(255,179,71,.08);border:1px solid rgba(255,179,71,.3);border-radius:12px;padding:16px;text-align:center;\">'\n        +'<div style=\"font-size:18px;margin-bottom:8px;\">\u26a0\ufe0f</div>'\n        +'<div style=\"font-family:Syne,sans-serif;font-weight:700;color:#ffb347;margin-bottom:8px;\">Has usado tus 3 consultas gratuitas del mes</div>'\n        +'<div style=\"font-size:13px;color:var(--text-muted);margin-bottom:14px;line-height:1.6;\">Si verificas clientes frecuentemente, reg\u00edstrate y obt\u00e9n hasta <strong style=\"color:var(--text);\">200 consultas mensuales</strong> desde <strong style=\"color:var(--accent);\">$9.900</strong></div>'\n        +'<button onclick=\"showScreen(\\'reg-step1\\')\" style=\"background:linear-gradient(135deg,var(--accent),#00b894);color:#001a14;border:none;border-radius:8px;padding:10px 20px;font-size:13px;font-weight:600;cursor:pointer;font-family:Syne,sans-serif;width:100%;margin-bottom:8px;\">Registrarme \u2014 desde $0/mes</button>'\n        +'<button onclick=\"showScreen(\\'login\\')\" style=\"background:transparent;border:1px solid var(--border);color:var(--accent);border-radius:8px;padding:8px 20px;font-size:13px;cursor:pointer;font-family:Syne,sans-serif;width:100%;\">Ya tengo cuenta \u2014 Iniciar sesi\u00f3n</button>'\n        +'</div>';\n      return;\n    }\n    const { data: personas } = await supa.from('Tbl_Persona')\n      .select('id, Nro_documento')\n      .eq('Nro_documento', doc)\n      .eq('Id_tp_documento', parseInt(tipoId));\n\n    // Registrar consulta y alertar restantes\n    await registrarConsulta(doc, parseInt(tipoId), personas && personas.length > 0);\n    const restantes = limite.restantes - 1;\n    if (restantes === 0) toast('Has usado tu ultima consulta gratuita del mes. Registrate para mas.', 'info');\n    else if (restantes === 1) toast('Te queda 1 consulta gratuita este mes.', 'info');\n\n    if (!personas || personas.length === 0) {\n      div.style.display = 'block';\n      div.innerHTML = '<div style=\"text-align:center;padding:20px;background:rgba(0,212,170,.08);border:1px solid rgba(0,212,170,.2);border-radius:12px;color:var(--accent);\">\u2705 No se encontraron reportes de mora para este documento.</div>';\n      return;\n    }\n\n    const personaIds = personas.map(function(p){ return p.id; });\n    const { data: deudas } = await supa.from('Fac_deudas')\n      .select('id, Valor_total_deuda, Fecha_Vencimiento_deuda, Id_persona')\n      .in('Id_persona', personaIds)\n      .order('created_at', { ascending: false });\n\n    if (!deudas || deudas.length === 0) {\n      div.style.display = 'block';\n      div.innerHTML = '<div style=\"text-align:center;padding:20px;background:rgba(0,212,170,.08);border:1px solid rgba(0,212,170,.2);border-radius:12px;color:var(--accent);\">\u2705 No se encontraron reportes de mora para este documento.</div>';\n      return;\n    }\n\n    // Cargar datos completos \u2014 gratis para todos\n    const { data: deudasFull } = await supa.from('Fac_deudas')\n      .select('*, empresa:Id_empresa(id, Nombre_Empresa)')\n      .in('Id_persona', personaIds)\n      .order('created_at', { ascending: false });\n\n    const { data: persEmpresas } = await supa.from('Tbl_Persona_Empresa')\n      .select('persona_id, empresa_id, nombre_empresa, id_departamento, id_municipio')\n      .in('persona_id', personaIds);\n\n    var peMap = {};\n    (persEmpresas||[]).forEach(function(pe){\n      peMap[pe.persona_id+'_'+pe.empresa_id] = pe;\n    });\n\n    // Cargar nombres de departamentos y municipios\n    const deptoIds = [...new Set((persEmpresas||[]).map(function(pe){ return pe.id_departamento; }).filter(Boolean))];\n    const mpioIds  = [...new Set((persEmpresas||[]).map(function(pe){ return pe.id_municipio; }).filter(Boolean))];\n\n    const { data: deptos } = deptoIds.length ? await supa.from('Tbl_Departamento').select('id, Nombre_Departamento').in('id', deptoIds) : { data: [] };\n    const { data: mpios  } = mpioIds.length  ? await supa.from('Tbl_municipios').select('id, Nombre_mpio').in('id', mpioIds) : { data: [] };\n\n    var deptoMap = {}; (deptos||[]).forEach(function(d){ deptoMap[d.id] = d.Nombre_Departamento; });\n    var mpioMap  = {}; (mpios||[]).forEach(function(m){ mpioMap[m.id]  = m.Nombre_mpio; });\n\n    let totalMora = 0;\n    let html = '<div style=\"background:rgba(255,77,109,.08);border:1px solid rgba(255,77,109,.2);border-radius:12px;padding:16px;\">';\n    html += '<div style=\"font-family:Syne,sans-serif;font-weight:700;font-size:16px;color:var(--danger);margin-bottom:4px;\">\u26a0 Documento reportado en mora</div>';\n    html += '<div style=\"font-size:13px;color:var(--text-muted);margin-bottom:14px;\">Doc: '+doc+' \u2014 <strong>'+(deudasFull||[]).length+' obligaci\u00f3n(es)</strong></div>';\n\n    (deudasFull||[]).forEach(function(d) {\n      totalMora += parseFloat(d.Valor_total_deuda)||0;\n      const emp     = d.empresa ? d.empresa.Nombre_Empresa : '-';\n      const empId   = d.Id_empresa;\n      const pe      = peMap[d.Id_persona+'_'+empId] || {};\n      const pNombre = pe.nombre_empresa || '-';\n      const depto   = deptoMap[pe.id_departamento] || '-';\n      const mpio    = mpioMap[pe.id_municipio]     || '-';\n      const valor   = '$'+parseFloat(d.Valor_total_deuda).toLocaleString('es-CO',{maximumFractionDigits:0});\n      const fecha   = d.Fecha_Vencimiento_deuda ? new Date(d.Fecha_Vencimiento_deuda+'T00:00:00').toLocaleDateString('es-CO',{day:'2-digit',month:'short',year:'numeric'}) : '-';\n\n      html += '<div style=\"background:var(--surface2);border-radius:8px;padding:12px;margin-bottom:8px;font-size:13px;\">';\n      html += '<div style=\"font-weight:600;color:var(--accent);margin-bottom:4px;\">Cr\u00e9dito #'+d.id+'</div>';\n      html += '<div style=\"color:var(--text);margin-bottom:2px;\"><strong>Empresa:</strong> '+emp+'</div>';\n      html += '<div style=\"color:var(--text-muted);font-size:11px;margin-bottom:2px;\">Registrado como: '+pNombre+'</div>';\n      html += '<div style=\"color:var(--text-muted);font-size:11px;margin-bottom:4px;\">\ud83d\udccd '+depto+' \u2014 '+mpio+'</div>';\n      html += '<div style=\"color:var(--danger);font-weight:700;margin-bottom:4px;\">'+valor+'</div>';\n      html += '<div style=\"color:var(--text-muted);margin-bottom:6px;\">Vence: '+fecha+'</div>';\n      if (d.Observacion) html += '<div style=\"color:var(--text-muted);font-size:12px;margin-bottom:8px;\">'+d.Observacion+'</div>';\n      html += '<button onclick=\"abrirNegociacion('+d.id+','+empId+',\\''+emp.replace(/'/g,'')+'\\',\\''+valor+'\\')\" '\n        +'style=\"background:linear-gradient(135deg,var(--accent),#00b894);color:#001a14;border:none;border-radius:8px;'\n        +'padding:9px 16px;font-size:12px;font-weight:600;cursor:pointer;font-family:Syne,sans-serif;width:100%;margin-bottom:6px;\">'\n        +'\ud83e\udd1d Quiero negociar esta deuda</button>';\n      html += '<button onclick=\"abrirCorreccion('+d.id+','+empId+',\\''+emp.replace(/'/g,'')+'\\',\\''+valor+'\\')\" '\n        +'style=\"background:rgba(255,179,71,.1);border:1px solid rgba(255,179,71,.3);color:#ffb347;border-radius:8px;'\n        +'padding:8px 16px;font-size:12px;font-weight:600;cursor:pointer;font-family:Syne,sans-serif;width:100%;\">'\n        +'\ud83d\udccb Solicitar correcci\u00f3n</button>';\n      html += '</div>';\n    });\n\n    html += '<div style=\"font-size:13px;font-weight:700;color:var(--danger);margin-top:8px;\">Total en mora: $'+totalMora.toLocaleString('es-CO',{maximumFractionDigits:0})+'</div>';\n    html += '</div>';\n    div.style.display = 'block';\n    div.innerHTML = html;\n\n  } catch(e) {\n    toast('Error en consulta: '+e.message, 'error');\n  } finally {\n    btn.disabled = false; btn.textContent = '\ud83d\udd0d Consultar';\n  }\n}\n\n\n// \u2500\u2500 SIMULACI\u00d3N DE PAGO (por ahora) \u2500\u2500\nasync function simularPago(doc, tipoId) {\n  toast('Procesando pago...', 'info');\n  await new Promise(function(r){ setTimeout(r, 1500); });\n\n  await supa.from('Tbl_Pagos_Consulta').insert({\n    documento: doc,\n    tipo_documento_id: tipoId,\n    valor_pagado: 3000,\n    estado: 'completado',\n    referencia: 'DEMO-' + Date.now()\n  });\n\n  state.pnPagado = true;\n  state.pnDoc    = doc;\n  state.pnTipo   = tipoId;\n\n  toast('\u2705 Pago exitoso. Cargando detalle completo...', 'success');\n\n  // Recargar con detalle completo usando verificarPersona con flag pagado\n  document.getElementById('v-documento').value = doc;\n  document.getElementById('v-tipo-doc').value  = tipoId;\n  await verificarPersona();\n}\nfunction pedirEliminar(deudaId, nombre, personaId) {\n  deleteTarget = { deudaId: deudaId, personaId: personaId };\n  document.getElementById('delete-desc').textContent = 'Vas a eliminar el reporte de ' + nombre + '. Esta accion no se puede deshacer.';\n  document.getElementById('motivo-eliminacion').value = '';\n  document.getElementById('otro-motivo-wrap').style.display = 'none';\n  document.getElementById('otro-motivo').value = '';\n\n  // Mostrar campo \"otro\" cuando seleccione ese motivo\n  document.getElementById('motivo-eliminacion').onchange = function() {\n    document.getElementById('otro-motivo-wrap').style.display =\n      this.value === 'otro' ? 'block' : 'none';\n  };\n\n  document.getElementById('modal-delete').style.display = 'flex';\n}\n\nasync function confirmarEliminar() {\n  const motivo = document.getElementById('motivo-eliminacion').value;\n  if (!motivo) { toast('Selecciona el motivo de eliminacion', 'error'); return; }\n\n  const motivoFinal = motivo === 'otro'\n    ? (document.getElementById('otro-motivo').value.trim() || 'Otro motivo')\n    : motivo;\n\n  const deudaId   = deleteTarget.deudaId;\n  const personaId = deleteTarget.personaId;\n  cerrarModal('modal-delete');\n\n  const { data: deudaAnt } = await supa.from('Fac_deudas').select('*').eq('id', deudaId).single();\n\n  // Guardar motivo antes de eliminar\n  await supa.from('Fac_deudas').update({\n    estado: 'eliminada',\n    motivo_eliminacion: motivoFinal\n  }).eq('id', deudaId);\n\n  await supa.from('Fac_deudas').delete().eq('id', deudaId);\n  await registrarAuditoria('ELIMINACION', 'Fac_deudas', deudaId, deudaAnt, { motivo: motivoFinal });\n\n  const { data: otras } = await supa.from('Fac_deudas').select('id').eq('Id_persona', personaId);\n  if (!otras || otras.length === 0) await supa.from('Tbl_Persona').delete().eq('id', personaId);\n  toast('Reporte eliminado', 'info');\n  cargarMorosos();\n}\n\nasync function hacerLogout() {\n  await supa.auth.signOut();\n  state = { empresa: null, regData: {}, editDatosAnt: null };\n  showScreen('welcome');\n  toast('Sesion cerrada', 'info');\n}\n</script>\n</body>\n</html>\n";

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === "/" || path === "/index.html") {
      return new Response(HTML, { headers: { "Content-Type": "text/html;charset=UTF-8" } });
    }

    if (request.method === "OPTIONS") {
      return new Response(null, { headers: { "Access-Control-Allow-Origin": "*", "Access-Control-Allow-Methods": "POST, GET, OPTIONS", "Access-Control-Allow-Headers": "Content-Type" } });
    }

    if (path === "/functions/enviar-sms" && request.method === "POST") {
      try {
        const { celular, mensaje } = await request.json();
        const numero = "57" + celular.replace(/\D/g, "").slice(-10);
        const res = await fetch("https://" + env.INFOBIP_BASE_URL + "/sms/2/text/advanced", {
          method: "POST",
          headers: { "Authorization": "App " + env.INFOBIP_API_KEY, "Content-Type": "application/json" },
          body: JSON.stringify({ messages: [{ from: "PlataformaC5", destinations: [{ to: numero }], text: mensaje }] })
        });
        const data = await res.json();
        const status = data.messages && data.messages[0] ? data.messages[0].status.name : "UNKNOWN";
        return new Response(JSON.stringify({ ok: true, status }), { headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      } catch(e) {
        return new Response(JSON.stringify({ error: e.message }), { status: 500, headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      }
    }

    if (path === "/functions/crear-pago" && request.method === "POST") {
      try {
        const { plan, valor, empresa_id, empresa_nombre, celular } = await request.json();
        const referencia = "C5-" + plan.toUpperCase() + "-" + empresa_id + "-" + Date.now();
        const res = await fetch("https://integrations-api.bold.co/online/link/v1", {
          method: "POST",
          headers: { "Authorization": "x-api-key " + env.BOLD_API_KEY, "Content-Type": "application/json" },
          body: JSON.stringify({ amount_type: "CLOSE", amount: { currency: "COP", total_amount: valor }, description: "Plataforma C5 Plan " + plan, reference_id: referencia, customer: { name: empresa_nombre, phone: "57" + celular } })
        });
        const data = await res.json();
        return new Response(JSON.stringify(res.ok ? { url: data.payload.url, referencia } : { error: "Error pago" }), { headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      } catch(e) {
        return new Response(JSON.stringify({ error: e.message }), { status: 500, headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      }
    }

    if (path === "/functions/cambiar-contrasena" && request.method === "POST") {
      try {
        const { celular, password } = await request.json();
        const email = celular + "@plataformac5.com";
        const resUsers = await fetch(env.SUPABASE_URL + "/auth/v1/admin/users?email=" + encodeURIComponent(email), {
          headers: { "apikey": env.SUPABASE_SERVICE_KEY, "Authorization": "Bearer " + env.SUPABASE_SERVICE_KEY }
        });
        const usersData = await resUsers.json();
        const user = usersData.users && usersData.users[0];
        if (!user) return new Response(JSON.stringify({ error: "Usuario no encontrado" }), { status: 404, headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
        const res = await fetch(env.SUPABASE_URL + "/auth/v1/admin/users/" + user.id, {
          method: "PUT",
          headers: { "apikey": env.SUPABASE_SERVICE_KEY, "Authorization": "Bearer " + env.SUPABASE_SERVICE_KEY, "Content-Type": "application/json" },
          body: JSON.stringify({ password })
        });
        const data = await res.json();
        return new Response(JSON.stringify(res.ok ? { ok: true } : { error: data.message }), { headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      } catch(e) {
        return new Response(JSON.stringify({ error: e.message }), { status: 500, headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      }
    }

    return new Response("Not found", { status: 404 });
  }
};
